-- Vernen Legal Compliance — Washington State Compliance Rules (Seed Washington-1)
-- FORMATION, TAXATION, REPORTING, EMPLOYMENT categories
-- ~200 rules with real RCW citations
-- Created: April 5, 2026
-- NOTE: wa-form-001, wa-tax-001 to wa-tax-003, wa-rep-001, wa-emp-001 to wa-emp-007 exist in prior seeds.
--       This file uses INSERT OR IGNORE to avoid conflicts and starts IDs accordingly.

-- ============================================================
-- SECTION 1: FORMATION (30 rules) — wa-form-002 to wa-form-030
-- (wa-form-001 exists in seed.sql)
-- ============================================================

-- Washington Business Corporation Act (RCW 23B)
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-form-002', 'WA-FORM-002', 'Washington Corporation Formation — Articles of Incorporation', 'Domestic business corporations must file Articles of Incorporation with the Washington Secretary of State. Filing fee is $180 online, $230 paper. Articles must include corporate name (containing "Corporation," "Incorporated," "Company," or abbreviation), number of authorized shares, registered agent name and street address in Washington, and incorporator name and address. Name must be distinguishable from existing registered names on file.', 'FORMATION', 'STATE', 'WA', '["CORPORATION","S_CORP"]', '2024-01-01', 'RCW 23B.02.020; RCW 23B.02.010', 'https://www.sos.wa.gov/corps/register-business.aspx', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-form-003', 'WA-FORM-003', 'Washington Corporation Name Requirements', 'Corporate name must contain "Corporation," "Incorporated," "Company," "Limited," or an abbreviation. Name must be distinguishable on Secretary of State records from existing registered business names. Name reservation available for 180 days at $30 fee. Application may be filed online. Professional corporations must include "Professional Corporation" or "P.C." and file under RCW 18.100.', 'FORMATION', 'STATE', 'WA', '["CORPORATION","S_CORP"]', '2024-01-01', 'RCW 23B.04.010; RCW 23.95.100', 'https://www.sos.wa.gov/corps/', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-form-004', 'WA-FORM-004', 'Washington Corporation Bylaws and Organizational Meeting', 'After incorporation, the board of directors shall hold an organizational meeting to adopt bylaws, elect officers, and transact business. Bylaws may contain any provision for managing the corporation not inconsistent with law or articles. Board may amend bylaws unless articles reserve that power exclusively to shareholders. Emergency bylaws may be adopted for quorum and other requirements during an emergency under RCW 23B.03.030.', 'FORMATION', 'STATE', 'WA', '["CORPORATION","S_CORP"]', '2024-01-01', 'RCW 23B.02.060; RCW 23B.02.061; RCW 23B.10.200', 'https://www.sos.wa.gov/corps/', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-form-005', 'WA-FORM-005', 'Washington Corporation Stock Issuance and Authorized Shares', 'Articles must prescribe the classes of shares and the number of shares of each class the corporation is authorized to issue. Shares may have par value or no par value. Board determines consideration for which shares are issued. Treasury shares are authorized but unissued shares. Corporation may issue rights, options, or warrants for purchase of shares. Fractional shares may be issued or eliminated per RCW 23B.06.040.', 'FORMATION', 'STATE', 'WA', '["CORPORATION","S_CORP"]', '2024-01-01', 'RCW 23B.06.010; RCW 23B.06.210; RCW 23B.06.240', 'https://www.sos.wa.gov/corps/', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-form-006', 'WA-FORM-006', 'Washington Corporation Directors and Officers', 'Board of directors must have one or more members, as set in articles or bylaws. Directors elected at annual meeting of shareholders. Officers appointed by the board. Every corporation must have a president and a secretary; same person may hold both offices. Directors owe duties of care and loyalty. Business judgment rule applies per RCW 23B.08.300. No residency requirement for directors.', 'FORMATION', 'STATE', 'WA', '["CORPORATION","S_CORP"]', '2024-01-01', 'RCW 23B.08.010; RCW 23B.08.300; RCW 23B.08.400', 'https://www.sos.wa.gov/corps/', 1);

-- Washington LLC Act (RCW 25.15)
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-form-007', 'WA-FORM-007', 'Washington LLC Formation — Certificate of Formation', 'One or more persons may form an LLC by filing a Certificate of Formation with the Secretary of State. Filing fee is $200 online, $230 paper. Certificate must include LLC name (containing "Limited Liability Company" or "LLC" or "L.L.C."), registered agent name and address, duration (if not perpetual), and whether member-managed or manager-managed. Effective upon filing unless delayed effective date specified.', 'FORMATION', 'STATE', 'WA', '["LLC"]', '2024-01-01', 'RCW 25.15.071; RCW 25.15.076', 'https://www.sos.wa.gov/corps/', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-form-008', 'WA-FORM-008', 'Washington LLC Name Requirements', 'LLC name must contain "Limited Liability Company" or the abbreviation "LLC" or "L.L.C." Name must be distinguishable from other registered names on file with the Secretary of State. Name reservation available for 180 days at $30 fee. Professional LLCs must include "Professional Limited Liability Company" or "PLLC" and are governed by RCW 25.15.046.', 'FORMATION', 'STATE', 'WA', '["LLC"]', '2024-01-01', 'RCW 25.15.006; RCW 23.95.100', 'https://www.sos.wa.gov/corps/', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-form-009', 'WA-FORM-009', 'Washington LLC Operating Agreement', 'Washington strongly recognizes LLC operating agreements. An operating agreement governs relations among members and managers, allocation of profits and losses, management structure, transfer restrictions, and dissolution procedures. May be oral, written, or implied. LLC is not required to file operating agreement with the Secretary of State. Operating agreement may not eliminate the duty of loyalty or the obligation of good faith entirely.', 'FORMATION', 'STATE', 'WA', '["LLC"]', '2024-01-01', 'RCW 25.15.017; RCW 25.15.038', 'https://www.sos.wa.gov/corps/', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-form-010', 'WA-FORM-010', 'Washington LLC Member and Manager Liability Protection', 'Members and managers of a Washington LLC are not personally liable for the debts, obligations, or other liabilities of the LLC solely by reason of being a member or manager. Exceptions include personal guarantees, tortious conduct, and piercing the corporate veil under equitable principles. Charging order is the exclusive remedy by a judgment creditor against a member''s transferable interest per RCW 25.15.256.', 'FORMATION', 'STATE', 'WA', '["LLC"]', '2024-01-01', 'RCW 25.15.126; RCW 25.15.256', 'https://www.sos.wa.gov/corps/', 1);

-- Partnerships (RCW 25.05)
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-form-011', 'WA-FORM-011', 'Washington General Partnership Formation', 'A general partnership is formed by the association of two or more persons to carry on as co-owners a business for profit under the Revised Uniform Partnership Act (RCW 25.05). No filing required to form, but optional Statement of Partnership Authority may be filed with the Secretary of State. Partners are jointly and severally liable for all partnership obligations. Must obtain UBI number from Department of Revenue.', 'FORMATION', 'STATE', 'WA', '["PARTNERSHIP"]', '2024-01-01', 'RCW 25.05.055; RCW 25.05.100', 'https://www.sos.wa.gov/corps/', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-form-012', 'WA-FORM-012', 'Washington Limited Liability Partnership (LLP) Registration', 'A partnership may become an LLP by filing a Statement of Qualification with the Secretary of State. Filing fee is $175. The statement must include partnership name (containing "Limited Liability Partnership" or "L.L.P." or "LLP"), address, and brief statement of business. LLP status provides limited liability protection — a partner is not personally liable for partnership obligations solely by reason of being a partner. Must maintain LLP status through annual reporting.', 'FORMATION', 'STATE', 'WA', '["PARTNERSHIP"]', '2024-01-01', 'RCW 25.05.500; RCW 25.05.505', 'https://www.sos.wa.gov/corps/', 1);

-- Limited Partnerships (RCW 25.10)
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-form-013', 'WA-FORM-013', 'Washington Limited Partnership Formation', 'A limited partnership is formed by filing a Certificate of Limited Partnership with the Secretary of State. Filing fee is $200 online. Certificate must include LP name (containing "Limited Partnership" or "L.P." or "LP"), registered agent, and name and address of each general partner. Must have at least one general partner and one limited partner. General partners have unlimited liability; limited partners'' liability is limited to their investment.', 'FORMATION', 'STATE', 'WA', '["PARTNERSHIP"]', '2024-01-01', 'RCW 25.10.101; RCW 25.10.111', 'https://www.sos.wa.gov/corps/', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-form-014', 'WA-FORM-014', 'Washington Limited Liability Limited Partnership (LLLP)', 'A limited partnership may elect LLLP status by including a statement in its certificate. An LLLP provides limited liability protection to general partners as well as limited partners. The certificate must state that the partnership is a limited liability limited partnership. Name must contain "Limited Liability Limited Partnership" or "LLLP." General partners in an LLLP are not personally liable for LP obligations solely by reason of being a general partner.', 'FORMATION', 'STATE', 'WA', '["PARTNERSHIP"]', '2024-01-01', 'RCW 25.10.011; RCW 25.10.401', 'https://www.sos.wa.gov/corps/', 1);

-- Nonprofit Corporations (RCW 24.03A)
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-form-015', 'WA-FORM-015', 'Washington Nonprofit Corporation Formation', 'Nonprofit corporations are formed under the Washington Nonprofit Corporation Act (RCW 24.03A, effective January 1, 2022, replacing former RCW 24.03). File Articles of Incorporation with the Secretary of State. Filing fee is $30 online. Articles must include name, registered agent, whether membership or non-membership corporation, and purpose. Directors must be natural persons age 18 or older.', 'FORMATION', 'STATE', 'WA', '["NONPROFIT"]', '2024-01-01', 'RCW 24.03A.020; RCW 24.03A.025', 'https://www.sos.wa.gov/corps/', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-form-016', 'WA-FORM-016', 'Washington Nonprofit Corporation Governance Requirements', 'Nonprofit must have a board of at least three directors unless articles provide otherwise. Board manages affairs of the corporation. Officers must include president and secretary at minimum. Directors owe duties of care and loyalty to the corporation. Conflicts of interest must be disclosed and approved under RCW 24.03A.175. Nonprofit may have members with voting rights or may be a non-membership corporation governed solely by the board.', 'FORMATION', 'STATE', 'WA', '["NONPROFIT"]', '2024-01-01', 'RCW 24.03A.095; RCW 24.03A.175; RCW 24.03A.340', 'https://www.sos.wa.gov/corps/', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-form-017', 'WA-FORM-017', 'Washington Nonprofit Charitable Solicitation Registration', 'Nonprofits soliciting charitable contributions in Washington must register with the Secretary of State''s Charities Program before soliciting. Registration fee is $60. Must file annual renewal with financial information. Exemptions exist for religious organizations, educational institutions, and organizations receiving less than $50,000 in annual contributions using only volunteer solicitors. Failure to register is a violation of the Charitable Solicitations Act (RCW 19.09).', 'FORMATION', 'STATE', 'WA', '["NONPROFIT"]', '2024-01-01', 'RCW 19.09.065; RCW 19.09.075', 'https://www.sos.wa.gov/charities/', 1);

-- Annual Report and UBI
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-form-018', 'WA-FORM-018', 'Washington Unified Business Identifier (UBI) Number', 'All businesses operating in Washington must obtain a UBI number by registering with the Department of Revenue through the Business Licensing Service (BLS). The UBI serves as a single identifying number used by multiple state agencies including Department of Revenue, Employment Security Department, and Department of Labor & Industries. Registration is free. Must register within 30 days of starting business. Sole proprietors using their own name in an unchanged form are exempt from the trade name requirement but must still obtain a UBI.', 'FORMATION', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 19.02.020; RCW 19.02.070', 'https://dor.wa.gov/open-business/apply-business-license', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-form-019', 'WA-FORM-019', 'Washington Annual Report Filing Requirement', 'All business entities registered with the Secretary of State must file an Annual Report. Due by the last day of the anniversary month of formation or registration. Filing fee is $60 for all entity types. Report must include current principal office address, registered agent information, and names and addresses of governors (directors, managers, or general partners). Failure to file results in administrative dissolution or revocation after notice.', 'FORMATION', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 23.95.255; RCW 23.95.600', 'https://www.sos.wa.gov/corps/', 1);

-- Registered Agent
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-form-020', 'WA-FORM-020', 'Washington Registered Agent Requirements', 'Every entity registered with the Secretary of State must continuously maintain a registered agent in Washington. The registered agent must be an individual resident of Washington or a domestic or foreign entity authorized to do business in Washington. The agent must have a physical street address (not a P.O. Box) in Washington. Agent may be changed by filing a Statement of Change with the Secretary of State. If agent resigns, entity must appoint new agent within 60 days.', 'FORMATION', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 23.95.405; RCW 23.95.410; RCW 23.95.430', 'https://www.sos.wa.gov/corps/', 1);

-- Foreign Entity Registration
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-form-021', 'WA-FORM-021', 'Washington Foreign Entity Registration', 'Foreign entities transacting business in Washington must register with the Secretary of State by filing a Foreign Registration Statement. Filing fee is $200 for LLCs and corporations. Must maintain a registered agent in Washington. "Transacting business" includes having employees, an office, or tangible personal property in the state. Failure to register prevents the entity from maintaining a proceeding in Washington courts but does not impair the validity of contracts or corporate acts.', 'FORMATION', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 23.95.500; RCW 23.95.505; RCW 23.95.520', 'https://www.sos.wa.gov/corps/', 1);

-- Social Purpose Corporations (RCW 23B.25)
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-form-022', 'WA-FORM-022', 'Washington Social Purpose Corporation Formation', 'Washington allows formation of Social Purpose Corporations under RCW 23B.25. Articles must state that the corporation is a social purpose corporation and must include one or more social purposes. Social purposes may include promoting positive effects on employees, communities, environment, or other stakeholders. Directors may consider social purpose in addition to maximizing financial return. Must file an annual social purpose report. Existing corporations may convert to social purpose corporation by amending articles with 2/3 shareholder approval.', 'FORMATION', 'STATE', 'WA', '["CORPORATION"]', '2024-01-01', 'RCW 23B.25.020; RCW 23B.25.040; RCW 23B.25.050', 'https://www.sos.wa.gov/corps/', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-form-023', 'WA-FORM-023', 'Washington Social Purpose Corporation Reporting', 'Social purpose corporations must prepare and make publicly available an annual social purpose report within 180 days of fiscal year end. Report must describe the corporation''s efforts to promote its social purposes, circumstances hindering promotion of social purposes, and any process or measurement used to evaluate promotion of social purposes. Report must be posted on the corporation''s website. Failure to report does not subject the corporation to penalties but may affect stakeholder trust.', 'FORMATION', 'STATE', 'WA', '["CORPORATION"]', '2024-01-01', 'RCW 23B.25.050', 'https://www.sos.wa.gov/corps/', 1);

-- Cooperative Associations
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-form-024', 'WA-FORM-024', 'Washington Cooperative Association Formation', 'Cooperative associations are formed under RCW 23.86 (general cooperatives) or RCW 24.06 (mutual corporations). Five or more persons may form a cooperative by filing articles of incorporation with the Secretary of State. Articles must include the cooperative''s name (containing "cooperative" or "co-op"), purpose, capital structure, and governance provisions. Each member has one vote regardless of ownership share. Organized on a not-for-profit or limited-profit basis.', 'FORMATION', 'STATE', 'WA', '["CORPORATION","NONPROFIT"]', '2024-01-01', 'RCW 23.86.010; RCW 23.86.030', 'https://www.sos.wa.gov/corps/', 1);

-- Trade Name Registration
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-form-025', 'WA-FORM-025', 'Washington Trade Name (DBA) Registration', 'Any person or entity conducting business under a name other than their legal name must file a Trade Name Registration with the Department of Licensing. Fee is $5. Registration is valid for 5 years and may be renewed. Registration provides notice of the business name to the public but does not create exclusive rights. Filed by the individual county or statewide through the Department of Licensing. Failure to register may impair the ability to enforce contracts made under the trade name.', 'FORMATION', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 19.80.010; RCW 19.80.020', 'https://www.dol.wa.gov/business/tradenames.html', 1);

-- Washington Business License
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-form-026', 'WA-FORM-026', 'Washington State Business License', 'Most businesses operating in Washington must obtain a Washington State Business License. The license is obtained through the Business Licensing Service (BLS) when registering for a UBI number. License must be renewed annually. Many cities participate in the BLS system, allowing businesses to obtain city licenses through the same application. Some businesses require additional specialty licenses. License must be displayed at the business location.', 'FORMATION', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 19.02.020; RCW 19.02.070; RCW 19.02.800', 'https://dor.wa.gov/open-business/apply-business-license', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-form-027', 'WA-FORM-027', 'Washington City Business License Requirements', 'Over 80 Washington cities participate in the Business Licensing Service (BLS) system. Many additional cities require separate city business licenses. Seattle, Tacoma, Bellevue, and other large cities have their own license requirements with separate fees. Seattle general business license costs $110/year. Tacoma general license is $130/year. Businesses must verify license requirements with each city where they maintain a physical presence or conduct business.', 'FORMATION', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 35.90.020; SMC 6.208 (Seattle)', 'https://www.seattle.gov/finance-and-administrative-services/business-licenses-and-taxes', 1);

-- Dissolution
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-form-028', 'WA-FORM-028', 'Washington Voluntary Dissolution', 'Corporations dissolve by filing Articles of Dissolution after board and shareholder approval (majority of votes entitled to be cast). LLCs dissolve by filing a Certificate of Dissolution. Filing fee is $20 for both entity types. Must wind up affairs, discharge liabilities, and distribute remaining assets to shareholders or members. Must notify creditors by mail and publication. Tax clearance from Department of Revenue required before final dissolution is effective.', 'FORMATION', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 23B.14.020; RCW 25.15.296', 'https://www.sos.wa.gov/corps/', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-form-029', 'WA-FORM-029', 'Washington Administrative Dissolution and Reinstatement', 'The Secretary of State may administratively dissolve an entity for failure to file annual reports, maintain a registered agent, or pay required fees. Before dissolution, Secretary provides 60 days written notice. Entity may apply for reinstatement within 5 years of administrative dissolution by filing an application, paying all delinquent fees (including $60 per missed annual report plus $25 reinstatement penalty), and curing the default. Reinstatement relates back to the date of dissolution.', 'FORMATION', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 23.95.600; RCW 23.95.610; RCW 23.95.615', 'https://www.sos.wa.gov/corps/', 1);

-- Mergers and Conversions
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-form-030', 'WA-FORM-030', 'Washington Entity Conversion and Domestication', 'Washington permits entity conversions between entity types (e.g., LLC to corporation) under RCW 23.95.700 and domestication of foreign entities to Washington. Filing fee is $180 for conversion statement. Plan of conversion must be approved by members/shareholders as required by the governing statute for each entity type. Conversion does not affect the entity''s debts, obligations, or contracts. The converted entity is the same entity as before conversion.', 'FORMATION', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 23.95.700; RCW 23.95.705; RCW 23B.09A', 'https://www.sos.wa.gov/corps/', 1);


-- ============================================================
-- SECTION 2: TAXATION (47 rules) — wa-tax-004 to wa-tax-050
-- (wa-tax-001 to wa-tax-003 exist in seed.sql)
-- ============================================================

-- NO STATE INCOME TAX — Major Compliance Consideration
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-tax-004', 'WA-TAX-004', 'Washington Has No State Income Tax — Compliance Consideration', 'Washington does not impose a personal or corporate income tax. This was confirmed by the Washington State Constitution, Art. VII, Sec. 1, as interpreted by the courts. Businesses relocating to or forming in Washington must understand that revenue is taxed through the Business & Occupation (B&O) tax on gross receipts instead. Federal income tax obligations remain. The absence of income tax increases the relative impact of B&O, sales, and other Washington-specific taxes on total tax burden.', 'TAXATION', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'WA Constitution Art. VII; RCW 82.04', 'https://dor.wa.gov/taxes-rates', 1);

-- B&O Tax Detail
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-tax-005', 'WA-TAX-005', 'Washington B&O Tax — Retailing Classification', 'Retailing classification B&O tax rate is 0.471% of gross receipts. Applies to businesses making retail sales of tangible personal property, digital goods, and certain services. Retail sales include sales to consumers who are the final users of the goods. No deductions for cost of goods sold, labor, or other business expenses. Small business B&O tax credit available for businesses with taxable income below certain thresholds per RCW 82.04.4451.', 'TAXATION', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 82.04.250', 'https://dor.wa.gov/taxes-rates/business-occupation-tax', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-tax-006', 'WA-TAX-006', 'Washington B&O Tax — Service and Other Activities Classification', 'Service and Other Activities classification B&O tax rate is 1.5% of gross receipts. Applies to businesses providing services not specifically classified elsewhere, including professional services, consulting, and personal services. This is the highest standard B&O rate and applies as the default classification when no other specific classification applies. Businesses must self-classify their activities and may have income in multiple classifications.', 'TAXATION', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 82.04.290', 'https://dor.wa.gov/taxes-rates/business-occupation-tax', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-tax-007', 'WA-TAX-007', 'Washington B&O Tax — Manufacturing Classification', 'Manufacturing classification B&O tax rate is 0.484% of gross receipts. Applies to businesses engaged in manufacturing, processing, or fabricating articles for sale. Manufacturing includes assembling, processing, or otherwise preparing articles from raw materials or assembled parts. Multiple Activities Tax Credit (MATC) prevents double taxation when manufacturer also sells at retail or wholesale. Must report under manufacturing classification first.', 'TAXATION', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 82.04.240', 'https://dor.wa.gov/taxes-rates/business-occupation-tax', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-tax-008', 'WA-TAX-008', 'Washington B&O Tax — Wholesaling Classification', 'Wholesaling classification B&O tax rate is 0.484% of gross receipts. Applies to sales to other businesses for resale. Wholesale sales are sales of tangible personal property to persons who purchase for the purpose of resale. Seller must obtain a resale certificate from buyer to document the wholesale nature of the sale. Multiple Activities Tax Credit applies when business has both manufacturing and wholesale activities on the same products.', 'TAXATION', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 82.04.270', 'https://dor.wa.gov/taxes-rates/business-occupation-tax', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-tax-009', 'WA-TAX-009', 'Washington B&O Tax — Small Business Credit', 'The Small Business B&O Tax Credit provides graduated relief for small businesses. Businesses with taxable gross income below certain thresholds receive a credit against B&O tax liability. Maximum credit is $70 per month ($840 per year). Credit phases out as income increases. Available to all B&O classifications. Businesses with annual income under $28,000 receive the full credit. Credit is automatically calculated on the excise tax return.', 'TAXATION', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 82.04.4451', 'https://dor.wa.gov/taxes-rates/tax-incentives/small-business-bo-tax-credit', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-tax-010', 'WA-TAX-010', 'Washington B&O Tax — Filing Frequency', 'B&O tax filing frequency is determined by the Department of Revenue based on estimated tax liability. Monthly filers: estimated annual tax liability of $4,800 or more (due 25th of following month). Quarterly filers: $1,050–$4,800 estimated annual liability (due last day of month following quarter). Annual filers: under $1,050 estimated annual liability (due April 15). Late filing penalty is 5% of tax due per month up to 25%. Interest accrues at variable rate.', 'TAXATION', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 82.32.045; WAC 458-20-22801', 'https://dor.wa.gov/taxes-rates/business-occupation-tax', 1);

-- Sales and Use Tax Detail
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-tax-011', 'WA-TAX-011', 'Washington Sales Tax — Exemptions and Special Rates', 'Washington exempts groceries (food for home consumption), prescription drugs, and most medical devices from sales tax. Manufacturing machinery and equipment are exempt under RCW 82.08.02565. Digital goods and digital codes are taxable at regular rates. Prepared food (food sold with utensils or heated) is taxable. Agricultural products sold by producers are generally exempt. Clothing is fully taxable in Washington with no exemption.', 'TAXATION', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 82.08.0293; RCW 82.08.0297; RCW 82.08.02565', 'https://dor.wa.gov/taxes-rates/retail-sales-tax', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-tax-012', 'WA-TAX-012', 'Washington Use Tax', 'Use tax is imposed on the use of tangible personal property, digital goods, and certain services in Washington when retail sales tax was not paid at the time of purchase. Rate equals the combined state and local sales tax rate at the location of first use in Washington. Applies to out-of-state purchases, items removed from inventory for personal use, and property brought into Washington. Self-reported on the excise tax return or consumer use tax return for individuals.', 'TAXATION', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 82.12.010; RCW 82.12.020', 'https://dor.wa.gov/taxes-rates/use-tax', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-tax-013', 'WA-TAX-013', 'Washington Sales Tax — Remote Seller Nexus', 'Remote sellers with more than $100,000 in gross retail sales or 200 transactions sourced to Washington in the current or preceding calendar year must collect and remit sales tax. Marketplace facilitators (e.g., Amazon, eBay) must collect on behalf of marketplace sellers if the facilitator exceeds these thresholds. Destination-based sourcing applies — tax is calculated based on delivery address. Referral solicitors creating nexus per RCW 82.08.052.', 'TAXATION', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 82.08.052; RCW 82.08.0532', 'https://dor.wa.gov/taxes-rates/retail-sales-tax/marketplace-fairness-leveling-playing-field', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-tax-014', 'WA-TAX-014', 'Washington Local Sales Tax Rates and Sourcing', 'In addition to 6.5% state sales tax, local jurisdictions impose additional sales tax ranging from 0.5% to 4.0%, resulting in combined rates from 7.0% to 10.5%. Rates vary by location and are destination-based (delivery address determines rate). The Department of Revenue provides a tax rate lookup tool by address. Businesses must use correct local rates for each transaction. Rate changes occur quarterly on January 1, April 1, July 1, and October 1.', 'TAXATION', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 82.14.030; RCW 82.14.020', 'https://dor.wa.gov/taxes-rates/sales-and-use-tax-rates', 1);

-- Property Tax
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-tax-015', 'WA-TAX-015', 'Washington Property Tax — Business Personal Property', 'Businesses must report taxable personal property (equipment, furniture, supplies, leasehold improvements) on an annual listing filed with the county assessor by April 30. Tax rate varies by county (typically $8–$15 per $1,000 of assessed value). Exemption for personal property valued under $15,000 per business location. Real property is assessed at 100% of fair market value. State constitutional limit of 1% of assessed value for regular levies per RCW 84.52.050.', 'TAXATION', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 84.40.020; RCW 84.36.110; RCW 84.52.050', 'https://dor.wa.gov/taxes-rates/property-tax', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-tax-016', 'WA-TAX-016', 'Washington Property Tax — Senior and Disabled Exemptions', 'Property tax exemptions and deferrals available for seniors (61+), disabled persons, and veterans. Income thresholds determine level of exemption: full exemption if household income under $40,000 (adjusted periodically). Partial exemption available at higher income levels. Application filed with county assessor. Deferred property tax creates a lien on the property repayable upon sale or change of ownership. Nonprofit property used for exempt purposes may qualify for total exemption under RCW 84.36.', 'TAXATION', 'STATE', 'WA', '["SOLE_PROPRIETORSHIP","NONPROFIT"]', '2024-01-01', 'RCW 84.36.381; RCW 84.38.010', 'https://dor.wa.gov/taxes-rates/property-tax/property-tax-exemptions-and-deferrals', 1);

-- Real Estate Excise Tax (REET)
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-tax-017', 'WA-TAX-017', 'Washington Real Estate Excise Tax (REET) — Graduated Rates', 'Washington imposes REET on the sale of real property at graduated rates: 1.1% on the first $525,000; 1.28% from $525,001 to $1,525,000; 2.75% from $1,525,001 to $3,025,000; 3.0% on amounts above $3,025,000. Thresholds adjusted annually for inflation. Paid by the seller at time of sale. Local REET of 0.25% to 0.50% may also apply. Exemptions exist for transfers between spouses, transfers to governmental entities, and certain foreclosures. Controlling interest transfers in entities holding real property also subject to REET.', 'TAXATION', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 82.45.060; RCW 82.45.010', 'https://dor.wa.gov/taxes-rates/other-taxes/real-estate-excise-tax', 1);

-- Estate Tax
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-tax-018', 'WA-TAX-018', 'Washington Estate Tax', 'Washington imposes an estate tax on estates exceeding $2,193,000 (indexed for inflation). Graduated rates from 10% to 20%. No gift tax in Washington. Estate tax return due within 9 months of date of death. Extension of time to file available for 6 months. Washington estate tax is independent of federal estate tax and has a much lower exemption. Deductions available for federal estate tax paid, marital deduction, charitable deduction, and family-owned business deduction (up to $2.5M additional exclusion per RCW 83.100.048).', 'TAXATION', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 83.100.040; RCW 83.100.048', 'https://dor.wa.gov/taxes-rates/other-taxes/estate-tax', 1);

-- Capital Gains Tax Detail
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-tax-019', 'WA-TAX-019', 'Washington Capital Gains Tax — Exclusions and Deductions', 'The 7% capital gains tax excludes: real estate sales, assets held in retirement accounts, livestock/agricultural products, timber, commercial fishing privileges, and goodwill from sale of auto dealerships. Qualified small business stock exclusion available. Charitable donation deduction of up to $100,000 per year. Standard deduction of $270,000 (adjusted for inflation). Returns due April 15. Estimated tax payments required if liability exceeds $1,000. Upheld as an excise tax by WA Supreme Court in Quinn v. State (2023).', 'TAXATION', 'STATE', 'WA', '["SOLE_PROPRIETORSHIP","PARTNERSHIP","LLC"]', '2024-01-01', 'RCW 82.87.040; RCW 82.87.050; RCW 82.87.070', 'https://dor.wa.gov/taxes-rates/other-taxes/capital-gains-tax', 1);

-- Hazardous Substance Tax
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-tax-020', 'WA-TAX-020', 'Washington Hazardous Substance Tax', 'Tax imposed on the first possession of hazardous substances in Washington, including petroleum products, pesticides, and certain chemicals. Rate is 0.7% of the wholesale value of the substance. Funds the Model Toxics Control Act (MTCA) cleanup programs. First possessor (usually the manufacturer, importer, or wholesaler) is liable. Reported on the Combined Excise Tax Return. Exemptions for substances used in agricultural operations, certain recycled materials, and de minimis quantities.', 'TAXATION', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 82.21.020; RCW 82.21.030', 'https://dor.wa.gov/taxes-rates/other-taxes/hazardous-substance-tax', 1);

-- Timber Excise Tax
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-tax-021', 'WA-TAX-021', 'Washington Timber Excise Tax', 'Tax imposed on the privilege of harvesting timber in Washington. Stumpage value (the value of standing timber) is determined by the Department of Revenue and published semiannually by species and area. Rate is 5% of stumpage value. In lieu of property tax on timber. Harvesters must file a return within 5 months after the end of the calendar quarter in which timber was harvested. Small harvester option available for harvesters taking less than 2 million board feet per year.', 'TAXATION', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 84.33.041; RCW 84.33.074', 'https://dor.wa.gov/taxes-rates/other-taxes/timber-tax', 1);

-- Insurance Premiums Tax
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-tax-022', 'WA-TAX-022', 'Washington Insurance Premiums Tax', 'Insurance companies pay a premium tax of 2% on gross premiums written in Washington. Applies to all authorized insurers. Title insurers pay 2% of gross premiums. Ocean marine insurance is exempt. Surplus line brokers collect a 2% tax on gross premiums. Health maintenance organizations are subject to 2% tax. Tax is in lieu of most other state taxes except real and personal property taxes. Reported annually to the Office of the Insurance Commissioner.', 'TAXATION', 'STATE', 'WA', '["CORPORATION"]', '2024-01-01', 'RCW 48.14.020; RCW 48.14.090', 'https://www.insurance.wa.gov/', 1);

-- Unemployment Insurance
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-tax-023', 'WA-TAX-023', 'Washington Unemployment Insurance Tax — Employer Contributions', 'Employers pay UI tax on the first $67,600 of each employee''s wages (2024 taxable wage base). New employer rates vary by industry classification and range from 0.97% to 8.82%. Experienced employer rates are based on the employer''s benefit ratio (charges to the employer''s account divided by taxable payroll). Social cost factor added to all employer rates. Reported quarterly on the Employment Security Department Quarterly Tax Report. Contributions due by the last day of the month following the end of the quarter.', 'TAXATION', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 50.24.010; RCW 50.29.025', 'https://esd.wa.gov/employer-taxes', 1);

-- Workers' Comp
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-tax-024', 'WA-TAX-024', 'Washington Workers'' Compensation — State Fund Premiums', 'Washington is a monopolistic state fund state for workers'' compensation. Private workers'' comp insurance is NOT available. All employers must obtain coverage through the Department of Labor & Industries (L&I) or self-insure (requires net worth of at least $25M or posting security). Premiums calculated per worker-hour based on risk classification. Both employer and employee contribute. Rates set annually by L&I. Reported and paid quarterly. Approximately 350 risk classifications with rates from $0.10 to $10+ per hour.', 'TAXATION', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 51.16.060; RCW 51.14.010; RCW 51.16.035', 'https://www.lni.wa.gov/insurance/rates-risk-classes/', 1);

-- Paid Family and Medical Leave
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-tax-025', 'WA-TAX-025', 'Washington Paid Family Medical Leave (PFML) Premium', 'Total PFML premium rate for 2024 is 0.74% of wages. Employee pays approximately 72.76% of total premium; employer pays approximately 27.24%. Employers with fewer than 50 employees are not required to pay employer portion but must still collect and remit employee portion. Premium assessed on wages up to the Social Security wage base ($168,600 in 2024). Reported and remitted quarterly to the Employment Security Department. Small business assistance grants available for employers under 150 employees to offset costs.', 'TAXATION', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 50A.10.030; RCW 50A.24.010', 'https://paidleave.wa.gov/employers/', 1);

-- Long-Term Care (WA Cares Fund)
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-tax-026', 'WA-TAX-026', 'Washington Long-Term Care Tax — WA Cares Fund', 'The WA Cares Fund imposes a 0.58% premium on employee wages with no cap. Premium is paid entirely by the employee; employers are responsible for withholding and remitting. Effective July 1, 2023. Employees who purchased private long-term care insurance before November 1, 2021 could apply for an exemption by December 31, 2022. Self-employed individuals may opt in. Near-retirees and certain workers near the border may qualify for conditional exemptions. Benefits begin July 2026: up to $36,500 lifetime for long-term care services.', 'TAXATION', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 50B.04.080; RCW 50B.04.090', 'https://wacaresfund.wa.gov/', 1);

-- City B&O Taxes
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-tax-027', 'WA-TAX-027', 'Seattle City B&O Tax', 'Seattle imposes its own Business & Occupation tax separate from the state B&O tax. Rates: retailing 0.215%, services/other 0.415%, manufacturing 0.215%. Tax threshold: businesses with gross revenue under $100,000 within Seattle city limits are exempt. Small business credit available. Filed quarterly or annually based on estimated liability. Due 30 days after end of reporting period. Seattle B&O is NOT deductible against state B&O. Businesses must register with Seattle and file separately from state returns.', 'TAXATION', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'SMC 5.45.050; SMC 5.45.060', 'https://www.seattle.gov/finance-and-administrative-services/business-licenses-and-taxes/city-business-and-occupation-bo-tax', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-tax-028', 'WA-TAX-028', 'Tacoma City B&O Tax', 'Tacoma imposes a city B&O tax. Rates: retailing 0.1%, wholesaling 0.1%, services 0.2%, manufacturing 0.1%. Tax threshold: businesses with Tacoma gross receipts under $250,000 are exempt. Filed quarterly. Must register with Tacoma Finance Department. Separate from state B&O. Nexus based on physical presence, employees, or solicitation within Tacoma city limits. Utility services subject to separate utility tax rates.', 'TAXATION', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'TMC 6A.30.050', 'https://www.cityoftacoma.org/government/city_departments/finance/tax_and_license', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-tax-029', 'WA-TAX-029', 'Bellevue City B&O Tax', 'Bellevue imposes a city B&O tax on businesses with gross receipts exceeding $180,000 within Bellevue. Rate is 0.1427% for most classifications. Utility companies subject to separate rates. Filed quarterly. Must register with the Bellevue Finance Department. Due 30 days after the end of the quarter. Late penalty of 5% per month up to 25%. Interest on underpayments at 9% per year. Separate registration and filing from state B&O.', 'TAXATION', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'BCC 4.09.030', 'https://bellevuewa.gov/city-government/departments/finance/business-taxes', 1);

-- Lodging Tax
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-tax-030', 'WA-TAX-030', 'Washington Lodging Tax', 'State lodging tax of 6.5% (same as retail sales tax rate) applies to all lodging charges. Counties and cities may impose additional lodging taxes (typically 1–4% additional). Convention and trade center tax of up to 7% in King County. Lodging includes hotels, motels, short-term rentals (Airbnb, VRBO), RV parks, and campgrounds. Short-term rental platforms must collect and remit state and local lodging taxes. Tourism promotion area charges may apply in designated areas.', 'TAXATION', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 67.28.180; RCW 67.28.181', 'https://dor.wa.gov/taxes-rates/other-taxes/lodging-tax', 1);

-- Cannabis Excise Tax
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-tax-031', 'WA-TAX-031', 'Washington Cannabis Excise Tax', 'Washington imposes a 37% excise tax on retail sales of cannabis products (usable cannabis, cannabis concentrates, and cannabis-infused products). Tax is imposed on the buyer and collected by the licensed retailer. In addition, standard retail sales tax applies. Cannabis businesses are also subject to B&O tax. Federal 280E restrictions limit deductions for federal income tax purposes. Cannabis remains a Schedule I substance under federal law, creating unique compliance obligations. Licensed under the Liquor and Cannabis Board.', 'TAXATION', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 69.50.535', 'https://lcb.wa.gov/mjlicense/cannabis-702-taxes', 1);

-- Utility Tax
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-tax-032', 'WA-TAX-032', 'Washington Public Utility Tax', 'Public utility tax (PUT) applies to public and privately owned utilities at rates varying by type: electric light and power 3.873%, natural gas distribution 3.852%, telephone service 3.0%, water distribution 5.029%, sewage collection 3.852%. Reported on the Combined Excise Tax Return. In lieu of B&O tax for the utility activity. Cities may impose additional utility taxes (typically 2–8%). Public utility districts (PUDs) are subject to privilege taxes in lieu of property taxes on operating property.', 'TAXATION', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 82.16.020', 'https://dor.wa.gov/taxes-rates/other-taxes/public-utility-tax', 1);

-- Litter Tax
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-tax-033', 'WA-TAX-033', 'Washington Litter Tax', 'Litter tax applies to manufacturers, wholesalers, and retailers of products that commonly become litter. Rate is 0.015% of gross proceeds of sales for manufacturers and wholesalers. Retailers pay based on a per-location fee schedule. Funds the Waste Reduction, Recycling, and Litter Control Account. Reported on the Combined Excise Tax Return. Products include food, beverages, tobacco, newspapers, and other packaged goods.', 'TAXATION', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 82.19.010; RCW 82.19.020', 'https://dor.wa.gov/taxes-rates/other-taxes/litter-tax', 1);

-- Spirits Taxes
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-tax-034', 'WA-TAX-034', 'Washington Spirits Liter Tax and Sales Tax', 'Following privatization of spirits sales (Initiative 1183, 2011), Washington imposes a spirits liter tax of $3.7708 per liter on retail sales and $2.4408 per liter on wholesale distribution. An additional spirits sales tax of 20.5% on retail and 13.7% on wholesale applies. Retail spirits sales also subject to standard sales tax. Spirits taxes fund state general fund and local government. Licensed distributors and retailers must report and remit monthly.', 'TAXATION', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 82.08.150; RCW 66.24.290', 'https://lcb.wa.gov/', 1);

-- Solid Waste Collection Tax
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-tax-035', 'WA-TAX-035', 'Washington Solid Waste Collection Tax', 'Tax imposed on every person engaged in the business of collecting solid waste at a rate of 3.6% of gross income from solid waste collection. Reported on the Combined Excise Tax Return. In addition to any applicable B&O tax. Applied to residential and commercial solid waste collection services. Local government operated collection services may be subject to local utility taxes instead. Recycling collection is generally exempt.', 'TAXATION', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 82.18.010; RCW 82.18.020', 'https://dor.wa.gov/taxes-rates/other-taxes/solid-waste-collection-tax', 1);

-- Enhanced Food Fish Tax
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-tax-036', 'WA-TAX-036', 'Washington Enhanced Food Fish Tax', 'Tax imposed on the commercial landing and processing of food fish and shellfish in Washington. Rates vary by species: salmon 5.62%, other food fish 2.57%, shellfish 2.57%, oysters 0.09%. Collected from the first commercial possessor. Reported on the Combined Excise Tax Return. Separate from B&O tax. Funds go to general fund and various resource management programs. Treaty tribe catches are exempt. Processors may take credit for tax paid by the original commercial possessor.', 'TAXATION', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 82.27.020', 'https://dor.wa.gov/taxes-rates/other-taxes/enhanced-food-fish-tax', 1);

-- Tobacco Tax
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-tax-037', 'WA-TAX-037', 'Washington Tobacco Tax', 'Cigarette tax is $3.025 per pack of 20. Other tobacco products taxed at 95% of taxable selling price. Vapor products taxed at $0.09 per milliliter of solution. Cigarette tax paid by purchase of stamps from the Department of Revenue by licensed distributors. Other tobacco products tax reported monthly by distributors. Retail sales tax also applies. Penalties for unstamped cigarettes include seizure and forfeiture. Indian reservation sales subject to cigarette compact agreements.', 'TAXATION', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 82.24.020; RCW 82.26.020; RCW 82.25.005', 'https://dor.wa.gov/taxes-rates/other-taxes/tobacco-tax', 1);

-- Leasehold Excise Tax
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-tax-038', 'WA-TAX-038', 'Washington Leasehold Excise Tax', 'Tax imposed on the privilege of using or occupying publicly owned real or personal property. State rate is 12.84% of the contract rent (or fair market rent if no rent or below-market rent). Counties and cities may impose additional leasehold excise tax up to 6%. In lieu of property tax since public property is otherwise exempt. Applies to leases of public ports, airports, convention centers, and other government property. Lessor collects and remits. Reported on the Combined Excise Tax Return.', 'TAXATION', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 82.29A.030; RCW 82.29A.040', 'https://dor.wa.gov/taxes-rates/other-taxes/leasehold-excise-tax', 1);

-- Oil Spill Tax
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-tax-039', 'WA-TAX-039', 'Washington Oil Spill Response Tax', 'Tax of $0.04 per barrel (42 gallons) imposed on crude oil and petroleum products received at a marine terminal or transported by pipeline in Washington. Additional $0.01 per barrel oil spill administration tax. Funds the Oil Spill Prevention Account for cleanup and prevention. Reported quarterly. Imposed on the first person receiving the oil in Washington. Pipelines and marine terminals must be registered. Penalty for failure to report is 5% per month up to 25%.', 'TAXATION', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP"]', '2024-01-01', 'RCW 82.23B.020; RCW 82.23B.030', 'https://dor.wa.gov/taxes-rates/other-taxes/oil-spill-response-and-administration-taxes', 1);

-- Aircraft Excise Tax
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-tax-040', 'WA-TAX-040', 'Washington Aircraft Excise Tax', 'In lieu of personal property tax, an annual aircraft excise tax applies to all aircraft registered in Washington. Rate is 0.5% of fair market value per year for aircraft valued at $15,000 or more. Aircraft valued under $15,000 pay a flat fee. Tax due on the anniversary of the registration date. Administered by the Department of Revenue. Commercial aircraft used in interstate commerce may qualify for exemptions. Delinquent tax accrues 1% per month penalty.', 'TAXATION', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 82.48.020; RCW 82.48.030', 'https://dor.wa.gov/taxes-rates/other-taxes/aircraft-excise-tax', 1);

-- Fuel Tax
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-tax-041', 'WA-TAX-041', 'Washington Motor Vehicle Fuel Tax', 'Washington motor vehicle fuel tax is $0.494 per gallon for gasoline and diesel. Includes base rate plus transportation infrastructure charges. Collected at the distributor level. Exempt uses include agricultural, marine, and government. Refund claims available for exempt uses. Special fuel users (diesel for off-road equipment) file quarterly reports. Licensed fuel distributors must report monthly. Funds dedicated to transportation infrastructure per 18th Amendment to WA Constitution.', 'TAXATION', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 82.38.030', 'https://dor.wa.gov/taxes-rates/other-taxes/motor-vehicle-fuel-tax', 1);

-- B&O Tax — Technology
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-tax-042', 'WA-TAX-042', 'Washington B&O Tax — Royalties and Digital Products', 'Royalties received for the use of intellectual property in Washington are subject to B&O tax at 1.5% (service/other activities rate). Digital products including digital goods, digital codes, and digital automated services are subject to B&O and retail sales tax. Sourcing for digital products follows the cascading sourcing rules of RCW 82.32.730. SaaS (software as a service) is classified as a digital automated service and subject to retail sales tax when sold to consumers.', 'TAXATION', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 82.04.290; RCW 82.04.192', 'https://dor.wa.gov/taxes-rates/business-occupation-tax', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-tax-043', 'WA-TAX-043', 'Washington B&O Tax — International Services Exemption', 'Income from international activities may qualify for preferential B&O treatment. Services performed for persons outside the United States may be deductible under the international services deduction (RCW 82.04.4286). Exports of goods are generally exempt from B&O tax. Foreign business entities earning income in Washington are subject to B&O tax on Washington-sourced income. Apportionment rules apply for multistate businesses under RCW 82.04.462 (single sales factor for services).', 'TAXATION', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 82.04.4286; RCW 82.04.462', 'https://dor.wa.gov/taxes-rates/business-occupation-tax', 1);

-- Payroll-Related Taxes Summary
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-tax-044', 'WA-TAX-044', 'Washington Employer Payroll Tax Summary', 'Washington employers must withhold and remit: (1) No state income tax withholding required, (2) Workers'' comp premiums (employee share) to L&I quarterly, (3) PFML premiums (employee + employer share) to ESD quarterly, (4) WA Cares Fund premiums (employee share) to ESD quarterly, (5) UI contributions (employer only) to ESD quarterly. Federal withholding (income tax, FICA, FUTA) still applies. No local income tax withholding. Failure to remit withheld amounts subject to 100% responsible person penalty.', 'TAXATION', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 50.24; RCW 50A.10; RCW 50B.04; RCW 51.16', 'https://esd.wa.gov/employer-taxes', 1);

-- Tax Penalties
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-tax-045', 'WA-TAX-045', 'Washington Tax Penalties and Interest', 'Late filing penalty: 5% of tax due for the first month, 15% for the second month, 25% for the third month and beyond. Assessment penalty (underpayment discovered by DOR): 5% or $50, whichever is greater. Substantial underpayment penalty: 20% for underpaying by 25% or more. Evasion penalty: up to 150% of tax. Interest on underpayments at variable rate set by DOR (average 3-5%). Voluntary disclosure agreements available for businesses that self-report past-due tax liability.', 'TAXATION', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 82.32.090; RCW 82.32.050', 'https://dor.wa.gov/taxes-rates/tax-penalties', 1);

-- Tax Credits and Incentives
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-tax-046', 'WA-TAX-046', 'Washington B&O Tax Credits and Incentives', 'Key B&O tax credits include: High Technology R&D credit (expired for most, some extensions), Manufacturing Machinery & Equipment sales tax exemption, Rural County B&O credit (0.0011% of wages in qualified counties), International Services deduction, Small Business B&O credit, Multiple Activities Tax Credit, Workforce Education Investment credit. Many credits require advance application and reporting. Sunset dates apply to most incentive programs. Tax preference performance statements required per RCW 82.32.534.', 'TAXATION', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 82.04.4452; RCW 82.04.4461; RCW 82.04.44525', 'https://dor.wa.gov/taxes-rates/tax-incentives', 1);

-- Combined Excise Tax Return
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-tax-047', 'WA-TAX-047', 'Washington Combined Excise Tax Return', 'Washington businesses report B&O tax, retail sales tax, use tax, and most other state excise taxes on a single Combined Excise Tax Return. Filed electronically through the Department of Revenue''s online portal (My DOR). Filing frequency (monthly, quarterly, or annual) assigned by DOR based on estimated liability. All taxes for a period reported on one return. Amended returns may be filed within 4 years of the original due date. Statute of limitations for DOR assessment is 4 years from the due date.', 'TAXATION', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 82.32.045; RCW 82.32.050', 'https://dor.wa.gov/file-pay-taxes', 1);

-- Unclaimed Property
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-tax-048', 'WA-TAX-048', 'Washington Unclaimed Property Reporting', 'Businesses holding property (accounts, wages, refunds, gift certificates) for which the owner cannot be located must report and remit to the Department of Revenue after the applicable dormancy period (generally 3 years for most property, 1 year for wages, 5 years for traveler''s checks). Annual report due by November 1. Due diligence notice must be sent to last known address 60-120 days before reporting. Penalty for failure to report: 25% of value. Gift certificates exempt if expiration prohibited.', 'TAXATION', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 63.30.010; RCW 63.30.220', 'https://ucp.dor.wa.gov/', 1);

-- Multijurisdictional Tax
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-tax-049', 'WA-TAX-049', 'Washington Apportionment for Multistate Businesses', 'For service businesses earning income both inside and outside Washington, B&O tax applies only to the Washington-sourced portion. Single sales factor apportionment under RCW 82.04.462 determines the Washington share. Market-based sourcing applies — services are sourced to where the customer receives the benefit. For manufacturing, physical presence of manufacturing activity determines sourcing. Interstate commerce protections under P.L. 86-272 do NOT apply to B&O tax because B&O is a gross receipts tax, not an income tax.', 'TAXATION', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 82.04.462; RCW 82.04.067', 'https://dor.wa.gov/taxes-rates/business-occupation-tax/apportionment', 1);

-- Voluntary Disclosure
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-tax-050', 'WA-TAX-050', 'Washington Voluntary Disclosure Program', 'Businesses that have been operating in Washington without registering or paying required taxes may apply for a Voluntary Disclosure Agreement (VDA) with the Department of Revenue. Benefits include waiver of penalties, limited lookback period (typically 4 years), and structured payment plans. Must not have been contacted by DOR about the tax before applying. Application made through the Multistate Tax Commission or directly with DOR. Interest on past-due amounts is not waived.', 'TAXATION', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 82.32.080; WAC 458-20-228', 'https://dor.wa.gov/taxes-rates/tax-penalties/voluntary-disclosure-program', 1);


-- ============================================================
-- SECTION 3: REPORTING (29 rules) — wa-rep-002 to wa-rep-030
-- (wa-rep-001 exists in seed.sql)
-- ============================================================

-- Secretary of State Reporting
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-rep-002', 'WA-REP-002', 'Washington Annual Report — Content and Filing', 'Annual report filed with Secretary of State must include: entity name, UBI number, jurisdiction of formation, principal office address, registered agent name and address, names and addresses of all governors (directors, managers, general partners), nature of business, and email address. Filed online through Corporations & Charities Filing System. Late report results in delinquency notice; continued failure leads to administrative dissolution. $60 filing fee for all entity types.', 'REPORTING', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 23.95.255; WAC 434-112-070', 'https://www.sos.wa.gov/corps/', 1);

-- B&O Tax Reporting
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-rep-003', 'WA-REP-003', 'Washington B&O Tax Return — Monthly Filing', 'Monthly filers (estimated annual tax liability $4,800+) must file Combined Excise Tax Return by the 25th of the month following the reporting period. Report gross income by B&O classification, calculate tax, apply credits. Electronic filing required through My DOR portal. Must file even if no tax is due (zero return). Late returns subject to 5%/15%/25% graduated penalty. Amended returns may be filed within 4 years.', 'REPORTING', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 82.32.045; WAC 458-20-22801', 'https://dor.wa.gov/file-pay-taxes', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-rep-004', 'WA-REP-004', 'Washington B&O Tax Return — Quarterly Filing', 'Quarterly filers (estimated annual liability $1,050–$4,800) file Combined Excise Tax Return by the last day of the month following the quarter. Q1 due April 30, Q2 due July 31, Q3 due October 31, Q4 due January 31. Same reporting requirements as monthly filers. DOR may reassign filing frequency based on actual tax liability.', 'REPORTING', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 82.32.045; WAC 458-20-22801', 'https://dor.wa.gov/file-pay-taxes', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-rep-005', 'WA-REP-005', 'Washington B&O Tax Return — Annual Filing', 'Annual filers (estimated annual liability under $1,050) file Combined Excise Tax Return by April 15 for the preceding calendar year. Annual filing assigned by DOR. Must still file even if no business activity. Can request change to quarterly or monthly filing. Annual filers with seasonal business activity should consider voluntary quarterly filing for cash flow management.', 'REPORTING', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 82.32.045; WAC 458-20-22801', 'https://dor.wa.gov/file-pay-taxes', 1);

-- Sales Tax Reporting
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-rep-006', 'WA-REP-006', 'Washington Sales Tax Return Reporting', 'Sales tax reported on the same Combined Excise Tax Return as B&O tax. Must report gross sales, taxable sales, and tax collected by location code. Location codes determine local tax rates. Businesses with multiple locations must separately report each location. Over-collected tax must be remitted to DOR or refunded to the buyer. Under-collected tax is the seller''s liability. Resale certificates must be kept on file for exempt sales.', 'REPORTING', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 82.08.050; RCW 82.32.045', 'https://dor.wa.gov/file-pay-taxes', 1);

-- Employment Security Department Reporting
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-rep-007', 'WA-REP-007', 'Washington Quarterly Wage Reporting — Employment Security Department', 'Employers must file quarterly wage reports with the Employment Security Department (ESD) listing all employees, their Social Security numbers, hours worked, and gross wages paid during the quarter. Filed electronically through EAMS (Employer Account Management Services). Due by the last day of the month following the quarter end. Late filing penalty of $25 per employee or 10% of contributions due, whichever is greater. Must report even if no wages paid (zero report).', 'REPORTING', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 50.12.070; WAC 192-310-010', 'https://esd.wa.gov/employer-taxes/reporting', 1);

-- L&I Workers' Comp Reporting
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-rep-008', 'WA-REP-008', 'Washington L&I Workers'' Comp Quarterly Reports', 'Employers must file quarterly reports with the Department of Labor & Industries (L&I) reporting worker hours by risk classification. Report is used to calculate workers'' compensation premiums. Due by the last day of the month following the quarter (same schedule as ESD). Filed electronically through My L&I portal. Must report actual hours worked per employee per risk class. Failure to report accurately subjects employer to estimated premiums and penalties. Audit of records every 3 years on average.', 'REPORTING', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 51.16.060; WAC 296-17-31009', 'https://www.lni.wa.gov/insurance/insurance-requirements/reporting-premiums/', 1);

-- New Hire Reporting
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-rep-009', 'WA-REP-009', 'Washington New Hire Reporting', 'Employers must report all newly hired and rehired employees to the Division of Child Support (DCS) within 20 days of the hire date. Report must include employee name, address, SSN, date of hire, and employer name, address, and federal EIN. Filed electronically through the DCS new hire reporting portal, by fax, or by mail. Failure to report is subject to a penalty of $25 per employee ($500 if conspiracy between employer and employee). Required by federal law (42 USC 653a) administered at state level.', 'REPORTING', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 26.23.040; 42 USC 653a', 'https://www.dshs.wa.gov/esa/division-child-support/new-hire-reporting', 1);

-- PFML Reporting
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-rep-010', 'WA-REP-010', 'Washington Paid Family Medical Leave Quarterly Reporting', 'Employers report PFML premiums quarterly to the Employment Security Department. Report must include each employee''s hours worked and wages subject to premium. Premium rate is 0.74% of wages up to Social Security wage base, split between employer (27.24%) and employee (72.76%). Employers with fewer than 50 employees report employee-only portion. Filed through the same EAMS system as unemployment insurance. Due by the last day of the month following the quarter.', 'REPORTING', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 50A.10.030; WAC 192-510-025', 'https://paidleave.wa.gov/employers/', 1);

-- WA Cares Fund Reporting
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-rep-011', 'WA-REP-011', 'Washington WA Cares Fund Quarterly Reporting', 'Employers report WA Cares Fund (long-term care) premiums quarterly to ESD. Premium is 0.58% of employee wages (no cap). 100% employee-paid; employer responsible for withholding and remitting. Report must include employee names, SSNs, wages, and premium amounts. Exempt employees (those with approved private long-term care insurance exemptions) must still be reported but flagged as exempt. Filed through EAMS alongside PFML and UI reports.', 'REPORTING', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 50B.04.080; RCW 50B.04.090', 'https://wacaresfund.wa.gov/employers/', 1);

-- Environmental Reporting
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-rep-012', 'WA-REP-012', 'Washington Department of Ecology — Environmental Reporting', 'Businesses generating, transporting, or disposing of dangerous waste must report to the Department of Ecology. Annual Dangerous Waste Report due March 1 for large quantity generators (over 2,200 lbs/month). Smaller generators file biennial reports. Air quality permits require annual emissions reports. Water discharge permits (NPDES) require monthly or quarterly discharge monitoring reports (DMRs). Stormwater industrial permits require annual reports. All reports filed through Ecology''s online systems.', 'REPORTING', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 70A.300.030; WAC 173-303-220', 'https://ecology.wa.gov/regulations-permits/reporting-requirements', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-rep-013', 'WA-REP-013', 'Washington Toxic Release Inventory (TRI) Reporting', 'Facilities in designated SIC/NAICS codes with 10+ employees that manufacture, process, or use toxic chemicals above threshold quantities must file TRI reports with EPA and the Department of Ecology. Federal Form R due July 1 annually. Washington has additional reporting under the Community Right-to-Know provisions. Facilities must also maintain Material Safety Data Sheets (SDS) and submit to local emergency planning committees. State Emergency Response Commission coordinates reporting.', 'REPORTING', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP"]', '2024-01-01', 'RCW 70A.430; 42 USC 11023', 'https://ecology.wa.gov/regulations-permits/reporting-requirements/toxic-release-inventory', 1);

-- OSHA / DOSH Reporting
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-rep-014', 'WA-REP-014', 'Washington Workplace Safety Reporting — DOSH and Federal OSHA', 'Washington operates a state-plan OSHA program for public sector employees through the Division of Occupational Safety and Health (DOSH) within L&I. Private sector employers are under federal OSHA jurisdiction. All employers must: (1) maintain OSHA 300 log of work-related injuries/illnesses, (2) post OSHA 300A summary February 1-April 30, (3) report fatalities within 8 hours and hospitalizations/amputations/eye loss within 24 hours. DOSH enforces Washington Industrial Safety and Health Act (WISHA) standards for public employers.', 'REPORTING', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 49.17.060; 29 CFR 1904', 'https://www.lni.wa.gov/safety-health/', 1);

-- Corporate Transparency Act
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-rep-015', 'WA-REP-015', 'Washington Entities — Federal Beneficial Ownership Reporting (BOI)', 'Washington-formed entities subject to the federal Corporate Transparency Act (CTA) must file Beneficial Ownership Information (BOI) reports with FinCEN. Entities formed before 2024 had until January 1, 2025 (currently under litigation — check current status). Entities formed 2024+ must file within 90 days of formation. Must report all beneficial owners holding 25%+ ownership or substantial control. Exemptions for entities with 20+ employees, $5M+ revenue, and physical US office.', 'REPORTING', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","PARTNERSHIP"]', '2024-01-01', '31 USC 5336; 31 CFR 1010.380', 'https://www.fincen.gov/boi', 1);

-- Charity Reporting
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-rep-016', 'WA-REP-016', 'Washington Charitable Organization Annual Reporting', 'Registered charitable organizations must file annual renewals with the Secretary of State''s Charities Program. Renewal includes financial information (revenue, expenses, fundraising costs). Organizations with gross revenue over $3M or using paid solicitors must include audited financial statements. Renewal fee is $60. Due within 11.5 months of fiscal year end. Must also file IRS Form 990 series. Secretary of State may revoke registration for failure to file or filing false information.', 'REPORTING', 'STATE', 'WA', '["NONPROFIT"]', '2024-01-01', 'RCW 19.09.075; RCW 19.09.100', 'https://www.sos.wa.gov/charities/', 1);

-- Insurance Reporting
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-rep-017', 'WA-REP-017', 'Washington Insurance Company Annual Reporting', 'Licensed insurers must file annual statements with the Office of the Insurance Commissioner by March 1. Include financial statements, risk-based capital reports, actuarial opinions, and management discussion and analysis. NAIC annual statement filing required. Premium tax return due March 1. Market conduct annual statements may be required. Health insurers must file network adequacy reports and rate filings. Failure to file timely may result in fines up to $1,000 per day.', 'REPORTING', 'STATE', 'WA', '["CORPORATION"]', '2024-01-01', 'RCW 48.06.030; RCW 48.14.020', 'https://www.insurance.wa.gov/', 1);

-- Pay Transparency Reporting
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-rep-018', 'WA-REP-018', 'Washington Pay Transparency — Job Posting Requirements', 'Employers with 15 or more employees must include salary ranges or wage scales in all job postings (effective January 1, 2023). Applies to jobs that could be performed in Washington, including remote positions. Must also include a general description of benefits and other compensation. Applies to both internal and external postings. Violations subject to civil penalties. No private right of action for posting violations, but failure may support wage discrimination claims under RCW 49.58.', 'REPORTING', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 49.58.110; SB 5761 (2022)', 'https://www.lni.wa.gov/workers-rights/wages/equal-pay-opportunities-act/', 1);

-- Business Tax Reporting to Cities
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-rep-019', 'WA-REP-019', 'Washington City B&O Tax Reporting', 'Businesses subject to city B&O taxes must file separate returns with each applicable city. Seattle: quarterly or annual filing through Seattle''s online tax portal. Tacoma: quarterly filing through Tacoma''s system. Bellevue: quarterly. Each city has different thresholds, rates, classifications, and due dates. No unified city tax return. FileLocal (www.filelocal.com) provides combined filing for some participating cities. Businesses must independently determine city nexus for each jurisdiction.', 'REPORTING', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 35.102.030; SMC 5.55.040', 'https://www.filelocal.com/', 1);

-- Workers' Comp Claims Reporting
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-rep-020', 'WA-REP-020', 'Washington Workers'' Compensation Injury Reporting', 'Employers must report all workplace injuries and occupational diseases to L&I. Worker files a claim (Report of Industrial Injury or Occupational Disease) through the online portal or paper form. Employer must file the Employer''s Report of Accident within 8 days of knowledge of the injury. Self-insured employers handle claims directly but must report to L&I. Failure to report timely may result in penalties. All claim information must be maintained for the duration of the claim plus 5 years.', 'REPORTING', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 51.28.010; RCW 51.28.020; WAC 296-20-015', 'https://www.lni.wa.gov/claims/', 1);

-- Capital Gains Tax Reporting
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-rep-021', 'WA-REP-021', 'Washington Capital Gains Tax Return', 'Individuals with long-term capital gains exceeding $270,000 must file a Washington Capital Gains Tax Return by April 15. Extensions available to October 15 with payment of estimated tax. Estimated tax payments due April 15 if expected liability exceeds $1,000. Reported on a separate return from the Combined Excise Tax Return. Must attach federal Schedule D and Form 8949. Penalties for late filing and underpayment apply. Jointly filed with DOR.', 'REPORTING', 'STATE', 'WA', '["SOLE_PROPRIETORSHIP","PARTNERSHIP","LLC"]', '2024-01-01', 'RCW 82.87.060; RCW 82.87.070', 'https://dor.wa.gov/taxes-rates/other-taxes/capital-gains-tax', 1);

-- REET Reporting
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-rep-022', 'WA-REP-022', 'Washington Real Estate Excise Tax Affidavit', 'REET affidavit must be filed with the county treasurer at time of real property sale or transfer. Affidavit includes seller and buyer information, property description, sale price, and tax calculation. Tax must be paid before recording the deed. Controlling interest transfers must be reported on a Controlling Interest Transfer Return filed with DOR within 5 days. County treasurers collect REET and remit the state portion to DOR. Late payment subject to 5-25% penalty plus interest.', 'REPORTING', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 82.45.090; RCW 82.45.150', 'https://dor.wa.gov/taxes-rates/other-taxes/real-estate-excise-tax', 1);

-- Data Breach Reporting
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-rep-023', 'WA-REP-023', 'Washington Data Breach Notification Reporting', 'Businesses that experience a data breach affecting Washington residents must notify affected individuals within 30 days of discovery. If breach affects more than 500 Washington residents, must also notify the Attorney General''s office. Notification must include description of the breach, types of personal information involved, and contact information. Covered personal information includes SSN, driver''s license, financial account numbers, health information, and biometric data. Encryption safe harbor applies.', 'REPORTING', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 19.255.010; RCW 19.255.020', 'https://www.atg.wa.gov/data-breach-notifications', 1);

-- Climate Commitment Act Reporting
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-rep-024', 'WA-REP-024', 'Washington Climate Commitment Act — Emissions Reporting', 'Facilities emitting 25,000+ metric tons of CO2 equivalent annually must report greenhouse gas emissions to the Department of Ecology. Part of Washington''s cap-and-invest program (Climate Commitment Act, enacted 2021). Covered entities must obtain allowances through auctions or the market. Annual emissions report due by March 31. Third-party verification required. First compliance period 2023-2026. Applies to large industrial emitters, fossil fuel suppliers, natural gas distributors, and waste facilities.', 'REPORTING', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP"]', '2024-01-01', 'RCW 70A.65.010; WAC 173-441', 'https://ecology.wa.gov/air-climate/climate-commitment-act', 1);

-- Alcohol and Cannabis Reporting
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-rep-025', 'WA-REP-025', 'Washington Cannabis Traceability Reporting', 'Licensed cannabis producers, processors, and retailers must report all cannabis inventory movements through the Washington State Liquor and Cannabis Board''s traceability system. Every plant, harvest, transfer, and sale must be tracked seed-to-sale. Monthly tax returns reporting cannabis excise tax due by the 20th of the following month. Inventory discrepancies exceeding thresholds must be reported within 24 hours. Violations subject to fines, suspension, or revocation of license.', 'REPORTING', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 69.50.345; WAC 314-55-083', 'https://lcb.wa.gov/', 1);

-- Professional License Reporting
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-rep-026', 'WA-REP-026', 'Washington Professional License Renewal Reporting', 'Businesses requiring professional licenses must file renewal reports with the Department of Licensing or applicable licensing board. Over 40 professional licensing boards operate in Washington. Renewal periods vary (1-4 years depending on profession). Continuing education requirements must be documented and retained. Failure to renew results in lapse of licensure and prohibition on practicing. Licensed professions include contractors, real estate agents, engineers, accountants, attorneys, and healthcare professionals.', 'REPORTING', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 18.04 (CPAs); RCW 18.27 (Contractors); RCW 18.85 (Real Estate)', 'https://www.dol.wa.gov/', 1);

-- Prevailing Wage Reporting
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-rep-027', 'WA-REP-027', 'Washington Prevailing Wage Reporting — Public Works', 'Contractors on public works projects must file Statements of Intent to Pay Prevailing Wages before work begins and Affidavits of Wages Paid upon completion. Filed with L&I. Prevailing wage rates set by L&I for each county and trade. Certified payroll records must be maintained and may be required for submission. Apprentice utilization requirements apply on projects over $1M. Violations subject to penalties of up to $5,000 per violation plus back wages. Retainage cannot be released without approved affidavit.', 'REPORTING', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 39.12.040; RCW 39.12.050', 'https://www.lni.wa.gov/licensing-permits/public-works-projects/', 1);

-- Property Tax Listing
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-rep-028', 'WA-REP-028', 'Washington Personal Property Tax Listing', 'Businesses must file an annual personal property listing with the county assessor by April 30 for property owned as of January 1. Lists all taxable personal property including equipment, machinery, furniture, fixtures, and supplies at original cost less depreciation. Exemption for personal property valued under $15,000 per location. Penalty for failure to list: 100% addition to assessed value. Assessor may estimate value if listing not filed. Business must retain records supporting reported values.', 'REPORTING', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 84.40.020; RCW 84.40.080', 'https://dor.wa.gov/taxes-rates/property-tax', 1);

-- Contractor Registration Reporting
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-rep-029', 'WA-REP-029', 'Washington Contractor Registration Renewal', 'All construction contractors must register with L&I and renew every 2 years. Registration fee is $163. Must maintain a surety bond ($12,000 for general contractors, $6,000 for specialty). Must carry current workers'' comp and liability insurance. Unregistered contracting is a gross misdemeanor. Advertising without registration number is a violation. Must include registration number on all contracts, bids, and advertising. L&I maintains a public lookup tool for verification.', 'REPORTING', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 18.27.020; RCW 18.27.040', 'https://www.lni.wa.gov/licensing-permits/contractors/', 1);

-- Whistleblower Reporting
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-rep-030', 'WA-REP-030', 'Washington Whistleblower Reporting Obligations', 'Employers must not retaliate against employees who report violations of law to a governmental body or who refuse to carry out a directive that would violate law. Public employers must post notice of employee whistleblower rights. State agencies must maintain internal reporting procedures. Reports of improper government action go to the State Auditor''s Office. Private sector whistleblower claims filed with L&I within 90 days of the retaliatory action. Remedies include reinstatement, back pay, and attorney fees.', 'REPORTING', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 42.40.010 (public); RCW 49.60.210 (private)', 'https://www.lni.wa.gov/workers-rights/workplace-policies/whistleblower-retaliation', 1);


-- ============================================================
-- SECTION 4: EMPLOYMENT (90 rules) — wa-emp-101 to wa-emp-190
-- (wa-emp-001 to wa-emp-007 exist in prior seeds)
-- ============================================================

-- Minimum Wage
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-emp-101', 'WA-EMP-101', 'Washington Minimum Wage — State Rate and Annual Adjustment', 'Washington state minimum wage is $16.28 per hour (2024), one of the highest in the nation. Adjusted annually based on Consumer Price Index for Urban Wage Earners (CPI-W) per Initiative 1433 (2016). No tip credit allowed — tipped employees must receive full minimum wage. No subminimum wage for youth under 16 (eliminated). Agricultural workers covered at the same minimum wage rate. Domestic workers covered. Local jurisdictions may set higher rates.', 'EMPLOYMENT', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 49.46.020; Initiative 1433', 'https://www.lni.wa.gov/workers-rights/wages/minimum-wage/', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-emp-102', 'WA-EMP-102', 'Seattle Minimum Wage', 'Seattle minimum wage exceeds state rate. Large employers (501+ employees): $19.97/hour (2024). Small employers (500 or fewer): $19.97/hour if employer pays toward medical benefits and/or employee earns tips of at least $2.72/hour, otherwise $19.97/hour. Adjusted annually on January 1. Applies to all employees who perform at least 2 hours of work in a workweek within Seattle. Seattle minimum wage applies regardless of employer''s location.', 'EMPLOYMENT', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'SMC 14.19.030; Ordinance 124490', 'https://www.seattle.gov/laborstandards/ordinances/minimum-wage', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-emp-103', 'WA-EMP-103', 'SeaTac and Other Local Minimum Wages', 'The city of SeaTac requires certain hospitality and transportation employers to pay $19.71/hour (2024, adjusted annually). Tukwila requires large employers to pay $20.29/hour (2024) and small employers $18.29/hour. Other cities may adopt higher minimums. Employers must comply with the highest applicable rate (federal, state, or local). Local minimum wage ordinances typically include anti-retaliation provisions protecting employees who assert their rights.', 'EMPLOYMENT', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'SeaTac Proposition 1 (2013); Tukwila Prop 1 (2022)', 'https://www.lni.wa.gov/workers-rights/wages/minimum-wage/', 1);

-- Overtime
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-emp-104', 'WA-EMP-104', 'Washington Overtime Requirements', 'Non-exempt employees must receive overtime pay at 1.5 times regular rate for hours worked over 40 in a workweek. Washington adopted new overtime salary threshold rules aligning with approximately 2x state minimum wage (phased in through 2028). For 2024, salaried employees earning less than $1,302.40/week must receive overtime. Agricultural workers now covered by overtime for hours over 40/week (phased in 2022-2024). No daily overtime requirement (unlike California). Compensatory time in lieu of overtime only for public employers.', 'EMPLOYMENT', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 49.46.130; WAC 296-128-500', 'https://www.lni.wa.gov/workers-rights/wages/overtime/', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-emp-105', 'WA-EMP-105', 'Washington Overtime Exemptions — Executive, Administrative, Professional', 'Exemptions from overtime for executive, administrative, and professional employees require meeting both duties test and salary threshold. 2024 salary threshold: $1,302.40/week ($67,724.80 annually) for large employers (51+), $1,101.80/week for small employers (1-50). Computer professionals: $56.98/hour or $5,456.12/month. Outside sales exemption requires customarily and regularly working away from employer''s place of business. Creative professional exemption for artists, writers, musicians. Teachers and academic administrators exempt.', 'EMPLOYMENT', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'WAC 296-128-500 through 296-128-545', 'https://www.lni.wa.gov/workers-rights/wages/overtime/changes-to-overtime-rules', 1);

-- Meal and Rest Breaks
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-emp-106', 'WA-EMP-106', 'Washington Meal Break Requirements', 'Employees must receive a meal period of at least 30 minutes for shifts over 5 hours. Meal period must begin no earlier than 2 hours and no later than 5 hours from the start of the shift. For shifts over 10 hours, a second meal period required. Meal periods may be unpaid if the employee is completely relieved of duties. If the employee is required to remain on duty or on the premises, the meal period is paid. Employer may not impose conditions that make a meal period impractical.', 'EMPLOYMENT', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'WAC 296-126-092', 'https://www.lni.wa.gov/workers-rights/wages/getting-paid/breaks-rest-periods', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-emp-107', 'WA-EMP-107', 'Washington Rest Break Requirements', 'Employees must receive a paid rest period of at least 10 minutes for each 4 hours worked. Rest period must be scheduled as near the midpoint of the 4-hour work period as practical. Rest periods are paid time and counted as hours worked. Employer may not require employees to remain on the work site during rest periods (unless the nature of work prevents the employee from being relieved). Healthcare employees have additional rest break protections under RCW 49.28.130.', 'EMPLOYMENT', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'WAC 296-126-092; RCW 49.28.130', 'https://www.lni.wa.gov/workers-rights/wages/getting-paid/breaks-rest-periods', 1);

-- Paid Family and Medical Leave
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-emp-108', 'WA-EMP-108', 'Washington Paid Family and Medical Leave — Employee Eligibility and Benefits', 'Employees eligible after working 820 hours in the qualifying period (prior 4 of 5 completed calendar quarters). Benefits: up to 12 weeks family leave, 12 weeks medical leave, 16 weeks combined (18 weeks for pregnancy complications). Weekly benefit calculated as percentage of average weekly wage: 90% of first $1,000 plus 50% above, capped at $1,456/week (2024). Job protection for employees of employers with 50+ employees who have worked 12+ months.', 'EMPLOYMENT', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 50A.15.020; RCW 50A.15.060', 'https://paidleave.wa.gov/', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-emp-109', 'WA-EMP-109', 'Washington PFML — Employer Obligations', 'Employers must: (1) collect employee premium share through payroll deduction, (2) remit combined employer/employee premiums quarterly, (3) provide written notice to employees of PFML rights at hire and when leave is requested, (4) maintain health benefits during approved leave, (5) restore employee to same or equivalent position after leave. Small employers (<50) exempt from employer premium share but must still collect and remit employee share. Voluntary plans allowed as alternative with ESD approval.', 'EMPLOYMENT', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 50A.04.205; RCW 50A.04.225', 'https://paidleave.wa.gov/employers/', 1);

-- Paid Sick Leave
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-emp-110', 'WA-EMP-110', 'Washington Paid Sick Leave — Accrual and Use', 'All employees accrue at least 1 hour of paid sick leave for every 40 hours worked (Initiative 1433). No waiting period — accrual begins on first day of employment; use permitted after 90 days. Unused paid sick leave carries over year to year (no cap on accrual required, but employer may cap use at 40 hours/year if front-loaded). Use for employee or family member illness, medical appointments, domestic violence, sexual assault, stalking, or closure of child''s school/daycare for health reason.', 'EMPLOYMENT', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 49.46.200; RCW 49.46.210', 'https://www.lni.wa.gov/workers-rights/leave/paid-sick-leave/', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-emp-111', 'WA-EMP-111', 'Washington Paid Sick Leave — Employer Obligations', 'Employers must: (1) track accrued and used paid sick leave, (2) notify employees of their rights in writing at hire, (3) allow use in increments consistent with payroll system (not to exceed 1-hour minimum), (4) not require documentation for absences of 3 or fewer days unless pattern of abuse, (5) not retaliate against employees for using paid sick leave, (6) provide at least the accrued balance on each pay stub. Seattle, Tacoma, and SeaTac have local paid sick leave ordinances that may provide additional rights.', 'EMPLOYMENT', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 49.46.200; WAC 296-128-600 through 296-128-790', 'https://www.lni.wa.gov/workers-rights/leave/paid-sick-leave/', 1);

-- Washington Law Against Discrimination (WLAD)
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-emp-112', 'WA-EMP-112', 'Washington Law Against Discrimination — Protected Classes', 'WLAD prohibits employment discrimination based on race, color, creed, national origin, citizenship or immigration status, sex, sexual orientation, gender identity, marital status, age (40+), disability, use of a trained dog guide or service animal, HIV/AIDS or hepatitis C status, veteran or military status, political ideology (Seattle only), caste (Seattle only). Applies to employers with 8 or more employees. Broader protections than federal Title VII. Administered by the Washington State Human Rights Commission (WSHRC).', 'EMPLOYMENT', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 49.60.030; RCW 49.60.180', 'https://www.hum.wa.gov/', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-emp-113', 'WA-EMP-113', 'Washington WLAD — Reasonable Accommodation', 'Employers must provide reasonable accommodation for employees with disabilities unless undue hardship. Washington law requires an interactive process to determine effective accommodation. Pregnancy disability accommodation also required under WLAD. Broader definition of disability than ADA — includes physical, mental, or sensory conditions that are medically cognizable or diagnosable, or exist as a record or history, or are perceived to exist. Must engage in good-faith interactive process before denying accommodation.', 'EMPLOYMENT', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 49.60.180; WAC 162-22-052', 'https://www.hum.wa.gov/', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-emp-114', 'WA-EMP-114', 'Washington Sexual Harassment Prevention Requirements', 'Employers must take reasonable steps to prevent and address sexual harassment. Washington prohibits NDAs and non-disparagement clauses in employment agreements that prevent disclosure of sexual harassment or assault (RCW 49.44.211, effective 2022). Employers may not require employees to waive right to publicly pursue a cause of action for sexual harassment or assault. Employer liability for supervisor harassment and for co-worker harassment if employer knew or should have known and failed to take corrective action.', 'EMPLOYMENT', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 49.60.180; RCW 49.44.211', 'https://www.hum.wa.gov/', 1);

-- Pay Transparency and Equal Pay
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-emp-115', 'WA-EMP-115', 'Washington Pay Transparency — Salary Range Disclosure', 'Employers with 15 or more employees must disclose the wage scale or salary range in all job postings, including internal postings and postings through third parties. Must also include a general description of all benefits and other compensation offered. Applies to positions that could be performed in Washington, including remote work. Upon request, employer must provide the wage scale or salary range for the employee''s current position. Effective January 1, 2023. Penalties for violation determined by L&I.', 'EMPLOYMENT', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 49.58.110 (SB 5761, 2022)', 'https://www.lni.wa.gov/workers-rights/wages/equal-pay-opportunities-act/', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-emp-116', 'WA-EMP-116', 'Washington Salary History Ban', 'Employers may not seek the wage or salary history of an applicant from the applicant or a current or former employer, or require that an applicant''s prior wage or salary history meet certain criteria. If the applicant voluntarily discloses, employer may confirm but cannot use it as the sole basis for determining compensation. Applies to all employers regardless of size. Does not apply to actions taken pursuant to a federal or state law that specifically authorizes the use of salary history. Effective July 28, 2019.', 'EMPLOYMENT', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 49.58.100', 'https://www.lni.wa.gov/workers-rights/wages/equal-pay-opportunities-act/', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-emp-117', 'WA-EMP-117', 'Washington Equal Pay and Opportunities Act', 'Employers may not discriminate in compensation or career advancement opportunities based on sex. Wage differentials permitted only for seniority, merit, quantity/quality of production, bona fide regional differences, education/training/experience, or where reasonable and business necessity exists. Employer must provide equal career advancement opportunities regardless of sex. Employees may discuss wages and compensation without retaliation. Statute of limitations is 3 years. Damages include back pay, front pay, and actual damages.', 'EMPLOYMENT', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 49.58.010 through 49.58.110', 'https://www.lni.wa.gov/workers-rights/wages/equal-pay-opportunities-act/', 1);

-- Noncompete Restrictions
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-emp-118', 'WA-EMP-118', 'Washington Noncompete Agreement Restrictions', 'Noncompete agreements are void and unenforceable against employees earning less than $116,593.18/year (2024, adjusted annually). For independent contractors, threshold is $291,483/year. Maximum duration is 18 months. Employer must disclose the terms of the noncompete in writing no later than the time of acceptance of the offer of employment or, for current employees, must provide independent consideration. Garden leave required for laid-off employees. Moonlighting restrictions are treated as noncompetes.', 'EMPLOYMENT', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 49.62.010; RCW 49.62.020', 'https://www.lni.wa.gov/workers-rights/workplace-policies/non-compete-agreements', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-emp-119', 'WA-EMP-119', 'Washington Noncompete — Enforcement and Penalties', 'An employer violating the noncompete statute is liable for actual damages or $5,000, whichever is greater, plus reasonable attorney fees and costs. Court may void the noncompete entirely. Employer must pay the employee during the noncompete period (garden leave) if the employee is terminated without cause. Nonsolicitation agreements of customers are NOT noncompete agreements and are not restricted under RCW 49.62 (but must still be reasonable). Franchisee noncompetes are treated as employee noncompetes.', 'EMPLOYMENT', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 49.62.080; RCW 49.62.060', 'https://www.lni.wa.gov/workers-rights/workplace-policies/non-compete-agreements', 1);

-- Ban the Box / Fair Chance Act
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-emp-120', 'WA-EMP-120', 'Washington Fair Chance Act — Ban the Box', 'Employers may not include questions about arrest records or convictions on job applications (RCW 49.94). May inquire about criminal history after initial screening determines the applicant is otherwise qualified. Must provide individualized assessment considering nature of crime, time elapsed, and nature of the job. Cannot advertise jobs in a way that excludes people with criminal records from applying. Applies to employers with 1+ employees. Seattle and other cities have additional fair chance hiring requirements.', 'EMPLOYMENT', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 49.94.010; RCW 49.94.020', 'https://www.lni.wa.gov/workers-rights/workplace-policies/criminal-records', 1);

-- Predictive Scheduling (Seattle)
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-emp-121', 'WA-EMP-121', 'Seattle Secure Scheduling Ordinance', 'Applies to retail and food service employers with 500+ employees worldwide and full-service restaurants with 500+ employees and 40+ locations worldwide. Must provide schedules 14 days in advance. Schedule changes with less than 14 days notice require premium pay: half the regular rate for changes. Employees may decline hours added after the schedule is posted without retaliation. Must offer additional hours to existing employees before hiring new workers. Predictability pay penalties range from $10 to full shift pay.', 'EMPLOYMENT', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP"]', '2024-01-01', 'SMC 14.22.015 through 14.22.110', 'https://www.seattle.gov/laborstandards/ordinances/secure-scheduling', 1);

-- Cannabis Employment Protections
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-emp-122', 'WA-EMP-122', 'Washington Cannabis Employment Protections', 'Employers may not discriminate against applicants based on off-duty cannabis use or the presence of non-psychoactive cannabis metabolites in pre-employment drug tests (effective January 1, 2024). Does not apply to: (1) positions requiring federal security clearance, (2) CDL holders, (3) safety-sensitive positions as defined by employer, (4) if employer would lose federal contract or funding. Employers may still prohibit impairment on the job. Post-employment testing not restricted. Does not prevent discipline for on-duty use.', 'EMPLOYMENT', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 49.44.240 (HB 1614, 2023)', 'https://www.lni.wa.gov/workers-rights/', 1);

-- Agricultural Worker Protections
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-emp-123', 'WA-EMP-123', 'Washington Agricultural Worker Protections — Overtime', 'Agricultural workers are now covered by overtime requirements (phased in 2022-2024). 2024 and beyond: overtime applies after 40 hours/week at 1.5x regular rate. Dairy workers included. H-2A temporary agricultural workers must be paid the Adverse Effect Wage Rate or prevailing wage. Agricultural employers must provide rest breaks, drinking water, sanitation facilities, and shade. Pesticide notification requirements under RCW 17.21. Farm labor contractors must be licensed with L&I.', 'EMPLOYMENT', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 49.46.130; HB 1267 (2021)', 'https://www.lni.wa.gov/workers-rights/wages/overtime/', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-emp-124', 'WA-EMP-124', 'Washington Agricultural Worker Housing Standards', 'Employers providing housing to agricultural workers must comply with Department of Health standards including structural safety, sanitation, potable water, heating, and adequate space. Housing must be inspected and licensed before occupancy. License fee is $10 per unit. Violations subject to penalties and immediate closure. Workers must be given at least 72 hours notice before housing closure. Free housing may not be used to reduce wages below minimum wage. DOH and L&I conduct joint inspections.', 'EMPLOYMENT', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 70.114A; WAC 246-358', 'https://www.doh.wa.gov/communityandenvironment/farmworkerhousing', 1);

-- Heat Illness Prevention
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-emp-125', 'WA-EMP-125', 'Washington Outdoor Heat Exposure Prevention', 'Permanent outdoor heat exposure rule effective 2023. When outdoor temperatures reach 80°F: employers must provide cool drinking water, sufficient shade, and mandatory cool-down rest periods. At 90°F: additional 10-minute paid preventive cool-down rest periods every 2 hours. At 100°F: cool-down periods every hour. New and unacclimated employees must be closely monitored during the first 14 days of heat exposure. Emergency medical plan required. Applies to all outdoor workers. L&I/DOSH enforces through inspections and citations.', 'EMPLOYMENT', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'WAC 296-62-095 through 296-62-09560', 'https://www.lni.wa.gov/safety-health/safety-topics/topics/outdoor-heat-exposure', 1);

-- Wildfire Smoke
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-emp-126', 'WA-EMP-126', 'Washington Wildfire Smoke Exposure Rule', 'Permanent wildfire smoke rule effective 2024. When the Air Quality Index for PM2.5 reaches 69+ (AQI "Unhealthy for Sensitive Groups"): employer must communicate about wildfire smoke hazards and encourage sensitive individuals to reduce exposure. At AQI 101+ ("Unhealthy"): must implement exposure controls (reduce outdoor time, provide N95 respirators for voluntary use, relocate work indoors). At AQI 201+ ("Very Unhealthy"): N95 respirators required for outdoor workers. Must monitor AQI throughout the workday.', 'EMPLOYMENT', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'WAC 296-62-085', 'https://www.lni.wa.gov/safety-health/safety-topics/topics/wildfire-smoke', 1);

-- Washington WARN Act
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-emp-127', 'WA-EMP-127', 'Washington WARN Act — Plant Closings and Mass Layoffs', 'Employers with 100 or more full-time employees must provide 60 days advance written notice before a plant closing or mass layoff (federal WARN Act applies; Washington does not have a separate state WARN Act but enforces federal). Plant closing: permanent or temporary shutdown of a single site affecting 50+ employees. Mass layoff: reduction of 33% and 50+ employees, or 500+ employees at a single site. Notice to affected employees, ESD, and local government. Failure to provide notice results in back pay and benefits for each day of violation.', 'EMPLOYMENT', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP"]', '2024-01-01', '29 USC 2101 (Federal WARN); RCW 50.20.110', 'https://esd.wa.gov/newsroom/WARN-layoff-notices', 1);

-- Workers' Compensation
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-emp-128', 'WA-EMP-128', 'Washington Workers'' Compensation — Mandatory Coverage', 'All employers in Washington must provide workers'' compensation coverage. Washington is a monopolistic state fund — private insurance is NOT available for standard workers'' comp. Coverage obtained through the Department of Labor & Industries (L&I). Self-insurance requires net worth of at least $25 million or acceptable security deposit and approval from L&I. Covers medical treatment, wage replacement (time-loss compensation at 60-75% of wages), permanent disability, and death benefits.', 'EMPLOYMENT', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 51.12.010; RCW 51.14.010', 'https://www.lni.wa.gov/insurance/', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-emp-129', 'WA-EMP-129', 'Washington Workers'' Comp — Employee vs. Employer Premiums', 'Both employer and employee contribute to workers'' comp premiums. Premiums calculated per worker-hour based on risk classification code. Employee portion covers the medical aid fund. Employer portion covers the accident fund and supplemental pension fund. Approximately 350 risk classifications. Rates published annually by L&I. Experience modification factors adjust premiums based on the employer''s claims history. Retrospective rating program available for large employers. Premiums reported and paid quarterly.', 'EMPLOYMENT', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 51.16.060; RCW 51.16.035', 'https://www.lni.wa.gov/insurance/rates-risk-classes/', 1);

-- Long-Term Care (WA Cares Act)
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-emp-130', 'WA-EMP-130', 'Washington WA Cares Act — Long-Term Care Employment Obligations', 'Employers must withhold 0.58% of employee wages (no cap) for the WA Cares Fund. No employer contribution required. Benefits begin July 2026: eligible individuals receive up to $36,500 lifetime benefit for long-term care services. Employees must have worked at least 500 hours in 3 of the last 6 years and contributed for 10 years without gap of 5+ years (or 3 years within last 6 years for near-retirees). Employers must maintain records of withholding and remit quarterly. Exempt employees must be tracked separately.', 'EMPLOYMENT', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 50B.04.020; RCW 50B.04.080', 'https://wacaresfund.wa.gov/', 1);

-- Whistleblower Protections
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-emp-131', 'WA-EMP-131', 'Washington Whistleblower Protection — Private Sector', 'Employers may not discharge or retaliate against an employee for filing a complaint with a governmental body about employer violations or for exercising rights under workplace safety laws. Retaliation claims filed with L&I within 90 days of the adverse action. Remedies include reinstatement, back pay, front pay, and attorney fees. Protection extends to employees who refuse to carry out a directive that they reasonably believe violates the law. Anti-retaliation applies to wage, safety, discrimination, and leave law complaints.', 'EMPLOYMENT', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 49.60.210; RCW 49.17.160', 'https://www.lni.wa.gov/workers-rights/workplace-policies/whistleblower-retaliation', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-emp-132', 'WA-EMP-132', 'Washington Whistleblower Protection — Public Sector', 'Public employees who report improper governmental action are protected under the State Employee Whistleblower Act (RCW 42.40). Reports may be made to the State Auditor. Improper governmental action includes violations of law, gross waste of funds, gross mismanagement, abuse of authority, and actions creating substantial danger to public health or safety. Retaliation is a civil offense. Remedies include reinstatement, back pay, injunctive relief, and reasonable attorney fees. 30-day administrative investigation timeline.', 'EMPLOYMENT', 'STATE', 'WA', '["NONPROFIT"]', '2024-01-01', 'RCW 42.40.010; RCW 42.40.040', 'https://www.sao.wa.gov/report-a-concern/how-to-report-a-concern/whistleblower/', 1);

-- Domestic Violence Leave
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-emp-133', 'WA-EMP-133', 'Washington Domestic Violence Leave', 'Employees who are victims of domestic violence, sexual assault, or stalking (or whose family members are victims) may take reasonable leave to: obtain legal or law enforcement assistance, seek medical treatment, obtain social services, relocate, or participate in safety planning. Applies to all employers regardless of size. Leave may be paid or unpaid (employer may allow employee to use accrued paid leave). Employer must maintain confidentiality of information related to the leave. Advance notice required when foreseeable.', 'EMPLOYMENT', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 49.76.010; RCW 49.76.030', 'https://www.lni.wa.gov/workers-rights/leave/domestic-violence-leave', 1);

-- Military and Veteran Protections
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-emp-134', 'WA-EMP-134', 'Washington Military Leave and Veteran Employment Protections', 'State employees receive 21 days paid military leave per year. Private employers must provide unpaid military leave with job restoration rights under USERRA (federal). Washington''s Military Family Leave Act allows employees to take up to 15 days of unpaid leave when a spouse or registered domestic partner is on leave from deployment or is about to be deployed. Employers may not discriminate against veterans or military members in hiring, retention, or promotion. WLAD protects veteran/military status.', 'EMPLOYMENT', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 73.16.032; RCW 49.77.010; 38 USC 4301 (USERRA)', 'https://www.lni.wa.gov/workers-rights/leave/military-related-leave', 1);

-- Child Labor
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-emp-135', 'WA-EMP-135', 'Washington Child Labor Laws', 'Minors under 18 must obtain a minor work permit from L&I before employment. 14-15 year olds: may not work during school hours, limited to 3 hours on school days, 8 hours on non-school days, 16 hours/week during school, 40 hours/week during breaks. Not before 7 AM or after 7 PM (9 PM June 1-Labor Day). 16-17 year olds: may not work more than 4 hours on school days or 28 hours during school weeks. Prohibited hazardous occupations apply. Parent/guardian written consent required.', 'EMPLOYMENT', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 49.12.121; RCW 49.12.123; WAC 296-125', 'https://www.lni.wa.gov/workers-rights/youth-employment/', 1);

-- Wage Payment
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-emp-136', 'WA-EMP-136', 'Washington Wage Payment Requirements', 'Employers must establish regular paydays occurring at least once per month. Wages earned in the first half of the month must be paid by the 25th of the same month; wages earned in the second half must be paid by the 10th of the following month. Pay stubs must include hours worked, rate of pay, gross and net wages, and all deductions. Direct deposit permitted only with employee written authorization. Employer may not deduct from wages except as required by law or authorized in writing by the employee.', 'EMPLOYMENT', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 49.48.010; RCW 49.52.050; WAC 296-126-023', 'https://www.lni.wa.gov/workers-rights/wages/getting-paid/', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-emp-137', 'WA-EMP-137', 'Washington Final Paycheck Requirements', 'Upon termination (voluntary or involuntary), all wages earned and unpaid must be paid by the next regular payday. No requirement for immediate payment. If employer willfully withholds wages, employee may recover double the amount wrongfully withheld plus costs and attorney fees per RCW 49.52.070. Accrued vacation pay must be paid at termination if the employer''s policy or practice provides for it. No state law requiring vacation payout, but if employer has a policy to pay it, the policy is enforceable.', 'EMPLOYMENT', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 49.48.010; RCW 49.52.050; RCW 49.52.070', 'https://www.lni.wa.gov/workers-rights/wages/getting-paid/', 1);

-- Pregnancy Accommodation
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-emp-138', 'WA-EMP-138', 'Washington Pregnancy Accommodation', 'Employers with 15 or more employees must provide reasonable accommodations for pregnancy and pregnancy-related conditions, including frequent restroom breaks, sitting while working, lifting limitations, temporary transfer to a less strenuous position, modified work schedule, and allowing more breaks for eating and drinking. No medical certification required for many standard accommodations. Employer must engage in interactive process. May not take adverse action because of accommodation request.', 'EMPLOYMENT', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 43.10.005; RCW 49.60.180; WAC 162-30-020', 'https://www.hum.wa.gov/', 1);

-- Lactation Accommodation
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-emp-139', 'WA-EMP-139', 'Washington Nursing Mother Accommodation', 'Employers must provide reasonable break time for employees to express breast milk for up to 2 years after the child''s birth. Must provide a private location (not a bathroom) near the employee''s work area to express milk. Location must be shielded from view and free from intrusion. Breaks may be unpaid unless employee uses paid break time. Must accommodate the employee''s need to express milk and may not discriminate or retaliate. These protections exceed federal PUMP Act requirements.', 'EMPLOYMENT', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 43.10.005; WAC 162-30-020', 'https://www.lni.wa.gov/workers-rights/', 1);

-- Recordkeeping
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-emp-140', 'WA-EMP-140', 'Washington Employment Recordkeeping Requirements', 'Employers must maintain employment records for at least 3 years including: employee name, address, occupation, dates of employment, rate of pay, hours worked each day, wages paid each pay period, and deductions. Must also retain hiring records, I-9 forms (3 years or 1 year after termination, whichever is later), and EEO-1 reports. Workers'' comp records must be retained for the duration of the claim plus 5 years. Tax records must be retained per statute of limitations (4+ years). Records must be available for L&I inspection.', 'EMPLOYMENT', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'WAC 296-126-025; RCW 49.46.070', 'https://www.lni.wa.gov/workers-rights/wages/getting-paid/', 1);

-- At-Will Employment
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-emp-141', 'WA-EMP-141', 'Washington At-Will Employment Doctrine', 'Washington is an at-will employment state. Either employer or employee may terminate the employment relationship at any time, for any reason or no reason, without liability. Exceptions: (1) violation of public policy (e.g., firing for exercising legal right), (2) implied contract (e.g., employee handbook creating implied promise of continued employment), (3) covenant of good faith, (4) whistleblower retaliation, (5) discrimination under WLAD. Disclaimers in handbooks should clearly state at-will status.', 'EMPLOYMENT', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'Washington common law; Thompson v. St. Regis Paper Co., 102 Wn.2d 219 (1984)', 'https://www.lni.wa.gov/', 1);

-- Independent Contractor Classification
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-emp-142', 'WA-EMP-142', 'Washington Independent Contractor Classification', 'Washington uses a multi-factor test to determine worker classification. For industrial insurance (workers'' comp), 6-part test under RCW 51.08.195 including: free from direction and control, independently established business, responsible for own costs, right to work for others, risk of loss, and filed business taxes. ESD uses a separate ABC test for unemployment insurance. Misclassification subjects employer to back taxes, penalties, and interest for all applicable programs (L&I, ESD, DOR). L&I actively audits classification.', 'EMPLOYMENT', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 51.08.195; RCW 50.04.140', 'https://www.lni.wa.gov/insurance/insurance-requirements/independent-contractors/', 1);

-- Workplace Safety (WISHA)
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-emp-143', 'WA-EMP-143', 'Washington Industrial Safety and Health Act (WISHA)', 'WISHA requires employers to provide a safe and healthful workplace. Washington DOSH enforces WISHA standards for public sector employers and some specialized areas. Private sector employers are under federal OSHA jurisdiction but must also comply with WISHA. Employers must: develop and implement a written Accident Prevention Program (APP), provide safety training, report serious injuries. Employee right to refuse unsafe work protected. Penalties for serious violations up to $7,000 per violation; willful violations up to $70,000.', 'EMPLOYMENT', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 49.17.010; RCW 49.17.060; WAC 296-800', 'https://www.lni.wa.gov/safety-health/', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-emp-144', 'WA-EMP-144', 'Washington Accident Prevention Program (APP) Requirement', 'All employers must develop and implement a written Accident Prevention Program (APP) per WAC 296-800-14005. The APP must include: management commitment and employee involvement, hazard identification and assessment, hazard prevention and control, safety training, and first aid procedures. Program must be reviewed and updated regularly. Must be tailored to the specific workplace hazards. Written program must be available for employee review. L&I provides templates. Failure to maintain APP is citable violation.', 'EMPLOYMENT', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'WAC 296-800-14005', 'https://www.lni.wa.gov/safety-health/safety-topics/accident-prevention-program/', 1);

-- Healthcare Worker Protections
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-emp-145', 'WA-EMP-145', 'Washington Healthcare Worker Overtime and Break Protections', 'Healthcare employees may not be required to work overtime (mandatory overtime prohibited for most healthcare workers). Exceptions for emergencies, critical services, and certain conditions. Uninterrupted rest and meal breaks required per RCW 49.28.130. Healthcare facilities must have documented staffing plans. Nurses and certain healthcare workers protected from retaliation for refusing mandatory overtime. Violations subject to fines of up to $10,000 per occurrence.', 'EMPLOYMENT', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","NONPROFIT"]', '2024-01-01', 'RCW 49.28.130; RCW 49.28.140', 'https://www.lni.wa.gov/workers-rights/leave/mandatory-overtime/', 1);

-- Paid Bereavement
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-emp-146', 'WA-EMP-146', 'Washington Bereavement Leave', 'While Washington does not have a standalone bereavement leave law, the PFML program covers bereavement for qualifying family members starting in 2024. Employees may take up to 7 days of paid family leave following the death of a qualifying family member. This is in addition to using accrued paid sick leave for bereavement purposes. Employers may also have bereavement policies providing additional leave. PFML bereavement available within 7 days of death or memorial service.', 'EMPLOYMENT', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 50A.05.010; RCW 49.46.210', 'https://paidleave.wa.gov/', 1);

-- Jury Duty
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-emp-147', 'WA-EMP-147', 'Washington Jury Duty Leave', 'Employers may not terminate, threaten, coerce, or penalize an employee for responding to a jury summons or serving on a jury. No requirement to pay wages during jury service, but employer may not deduct from salary of exempt employees for partial-week absences due to jury duty. Employee must give reasonable notice. Employee must be restored to former position without loss of seniority or benefits. Violation is a misdemeanor. Some collective bargaining agreements provide paid jury duty leave.', 'EMPLOYMENT', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 2.36.165', 'https://www.courts.wa.gov/jury/', 1);

-- Voting Leave
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-emp-148', 'WA-EMP-148', 'Washington Voting Leave', 'Washington conducts elections entirely by mail. Every registered voter receives a ballot by mail. No specific voting leave law exists because in-person voting is not the standard method. Ballot drop boxes and prepaid postage provided. Employers should not interfere with employees'' ability to complete and return ballots. Employer may not retaliate against employees for their political activities or voting. Election day is not a state holiday for private employers.', 'EMPLOYMENT', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 29A.40.010; RCW 29A.40.070', 'https://www.sos.wa.gov/elections/', 1);

-- E-Verify
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-emp-149', 'WA-EMP-149', 'Washington E-Verify and Employment Eligibility', 'Washington does not require private employers to use E-Verify (with limited exceptions for certain state contracts). All employers must complete I-9 forms. E-Verify is mandatory for federal contractors subject to FAR clause. Washington prohibits unfair immigration-related practices in employment under RCW 49.60. Employers may not threaten to report immigration status in retaliation for exercising workplace rights. Document abuse (demanding specific documents for I-9) is prohibited.', 'EMPLOYMENT', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 49.60.180; 8 USC 1324b', 'https://www.lni.wa.gov/workers-rights/', 1);

-- Workplace Violence Prevention
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-emp-150', 'WA-EMP-150', 'Washington Workplace Violence Prevention — Healthcare', 'Healthcare settings must have workplace violence prevention plans per RCW 49.19. Plans must include: hazard assessment, violence prevention and intervention procedures, incident reporting, employee training, and post-incident support. Security personnel must be available. Employers must track violent incidents and report to L&I. Expanded in 2019 to cover more healthcare settings. Training must be provided at hire and annually. Plans must be reviewed and updated annually.', 'EMPLOYMENT', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","NONPROFIT"]', '2024-01-01', 'RCW 49.19.010 through 49.19.060', 'https://www.lni.wa.gov/safety-health/safety-topics/workplace-violence/', 1);

-- Employee Leasing / PEO
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-emp-151', 'WA-EMP-151', 'Washington Professional Employer Organization (PEO) Requirements', 'PEOs operating in Washington must register with the Department of Licensing. PEO assumes certain employer obligations including workers'' comp coverage and payroll tax administration. Client employer retains direction and control of employees. Both PEO and client employer may be jointly liable for wage and hour violations. PEO must maintain financial surety and file annual reports. Workers'' comp coverage may be provided through the PEO''s L&I account or through the client employer''s account depending on the arrangement.', 'EMPLOYMENT', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 82.04.540; WAC 296-17-310', 'https://www.lni.wa.gov/', 1);

-- Employee Privacy
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-emp-152', 'WA-EMP-152', 'Washington Employee Privacy and Monitoring', 'Washington is a two-party consent state for recording conversations (RCW 9.73.030). Employers may not record private conversations without consent of all parties. Electronic monitoring of employees requires prior notice. Employer access to personal online accounts (social media passwords) prohibited under RCW 49.44.200. Employer may not require employee to disclose username or password for personal social media. Video monitoring in areas where employees have a reasonable expectation of privacy is prohibited.', 'EMPLOYMENT', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 9.73.030; RCW 49.44.200', 'https://www.lni.wa.gov/workers-rights/', 1);

-- Drug Testing
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-emp-153', 'WA-EMP-153', 'Washington Drug Testing in Employment', 'Washington does not have a comprehensive drug testing statute for private employers. Pre-employment testing permitted but may not test for non-psychoactive cannabis metabolites (RCW 49.44.240, effective 2024). DOT-regulated employees subject to federal testing requirements. Safety-sensitive position testing generally permitted. Post-accident testing permitted. Random testing permitted but not required (except DOT). Employer must have a clear written drug-free workplace policy. Positive test alone may not be sufficient for termination in all cases.', 'EMPLOYMENT', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 49.44.240; DOT 49 CFR Part 40', 'https://www.lni.wa.gov/workers-rights/', 1);

-- Ergonomics
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-emp-154', 'WA-EMP-154', 'Washington Ergonomics Compliance', 'Washington ergonomics rules were repealed by Initiative 841 (2003). However, employers still have a general duty under WISHA to provide a safe workplace free from recognized hazards. L&I provides voluntary ergonomics guidelines and consultation. Employers in high-risk industries (manufacturing, healthcare, agriculture) should maintain ergonomics programs to reduce musculoskeletal injury claims. Workers'' comp claims for repetitive motion injuries remain compensable. Prevention reduces premium costs under experience rating.', 'EMPLOYMENT', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 49.17.060 (general duty); Initiative 841 (2003)', 'https://www.lni.wa.gov/safety-health/safety-topics/ergonomics/', 1);

-- Leave for Organ/Bone Marrow Donation
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-emp-155', 'WA-EMP-155', 'Washington Leave for Organ and Bone Marrow Donation', 'State employees receive up to 30 days paid leave for organ donation and up to 7 days paid leave for bone marrow donation. Private employers are encouraged but not required to provide paid leave for organ/bone marrow donation. PFML may cover organ donation recovery as a serious health condition. FMLA protections apply if the employee qualifies. Employers may not discriminate against employees for taking leave related to organ or bone marrow donation.', 'EMPLOYMENT', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 41.04.340; RCW 50A.05.010', 'https://www.lni.wa.gov/workers-rights/leave/', 1);

-- Workplace Posters
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-emp-156', 'WA-EMP-156', 'Washington Required Workplace Posters', 'Employers must display required workplace posters including: "Your Rights as a Worker" (L&I), paid sick leave notice, PFML notice, minimum wage poster, Job Safety and Health (WISHA/OSHA), Notice to Employees — Workers'' Comp, unemployment insurance, "You Have the Right to Be Free from Discrimination" (WSHRC), federal posters (FLSA, FMLA, EEO, USERRA, OSHA). Posters must be in English and any other language spoken by 10% or more of the workforce. Electronic posting may supplement but not replace physical posting.', 'EMPLOYMENT', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 49.46.040; RCW 49.17.080', 'https://www.lni.wa.gov/forms-publications/f700-074-000.pdf', 1);

-- Commute Trip Reduction
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-emp-157', 'WA-EMP-157', 'Washington Commute Trip Reduction Law', 'Employers in counties with populations over 150,000 that have 100 or more employees at a single worksite must develop and implement a Commute Trip Reduction (CTR) program. Programs must encourage alternatives to single-occupant vehicle commuting (carpooling, transit, biking, telework). Must designate an Employee Transportation Coordinator. Survey employees biennially. Report progress to the local jurisdiction. Tax incentives available for employer-provided transit benefits. Goal: reduce vehicle miles traveled and greenhouse gas emissions.', 'EMPLOYMENT', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","NONPROFIT"]', '2024-01-01', 'RCW 70A.15.4000 through 70A.15.4100', 'https://wsdot.wa.gov/travel/commute-choices/commute-trip-reduction', 1);

-- Restrictive Covenants — Nonsolicitation
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-emp-158', 'WA-EMP-158', 'Washington Nonsolicitation and Confidentiality Agreements', 'Nonsolicitation agreements (of customers) are NOT regulated under the noncompete statute (RCW 49.62) and remain enforceable if reasonable in scope, geography, and duration. Confidentiality/trade secret agreements are similarly not restricted. However, confidentiality agreements may not prevent employees from discussing wages (protected activity) or from reporting illegal activity (whistleblower protection). Overbroad nonsolicitation agreements may be found to be de facto noncompetes and subject to RCW 49.62 restrictions.', 'EMPLOYMENT', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 49.62.010; Washington common law', 'https://www.lni.wa.gov/workers-rights/workplace-policies/non-compete-agreements', 1);

-- Construction Industry
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-emp-159', 'WA-EMP-159', 'Washington Construction Worker Protections', 'Construction workers have specific protections including: prevailing wage on public works projects (RCW 39.12), contractor registration requirement (RCW 18.27), mandatory workers'' comp coverage, fall protection standards (WAC 296-880), confined space rules, trenching and excavation standards, and silica exposure limits. All construction contractors must be registered with L&I. Subcontractors must verify prime contractor registration. Joint liability for wage violations on construction projects per RCW 39.12.065.', 'EMPLOYMENT', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 39.12; RCW 18.27; WAC 296-880', 'https://www.lni.wa.gov/licensing-permits/contractors/', 1);

-- Domestic Worker Protections
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-emp-160', 'WA-EMP-160', 'Washington Domestic Worker Protections — Domestic Workers Bill of Rights', 'Washington''s Domestic Workers Bill of Rights (HB 1723, effective 2020) provides domestic workers (nannies, housekeepers, home care workers) with: minimum wage, overtime after 40 hours, meal and rest breaks, paid sick leave, protection under WLAD, and workers'' comp coverage. Live-in domestic workers receive overtime after 44 hours/week. Written employment agreement required. Domestic employers must carry workers'' comp coverage through L&I. Exemption for casual domestic work (under 40 hours/quarter).', 'EMPLOYMENT', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 49.46.010; HB 1723 (2019)', 'https://www.lni.wa.gov/workers-rights/', 1);

-- Biometric Privacy
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-emp-161', 'WA-EMP-161', 'Washington Biometric Identifiers in Employment', 'Washington''s biometric identifier statute (RCW 19.375) restricts the use of biometric identifiers (fingerprints, retina/iris scans, voiceprints) in commercial contexts. Businesses may not collect, capture, or use biometric identifiers for a commercial purpose without first providing notice and obtaining consent. Employers using biometric time clocks or security systems must comply. No private right of action (enforced by Attorney General). Violations are per-se violations of the Consumer Protection Act. Data security requirements apply.', 'EMPLOYMENT', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 19.375.020', 'https://www.atg.wa.gov/', 1);

-- Silica Exposure
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-emp-162', 'WA-EMP-162', 'Washington Silica Dust Exposure Standards', 'Employers must comply with crystalline silica exposure standards. Permissible exposure limit (PEL) for respirable crystalline silica is 50 micrograms per cubic meter as an 8-hour TWA. Employers in construction must implement specified control methods per Table 1 or conduct exposure monitoring. Medical surveillance required for workers exposed above the action level (25 µg/m³) for 30+ days/year. Written exposure control plan required. Housekeeping methods that minimize airborne dust required.', 'EMPLOYMENT', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'WAC 296-840; 29 CFR 1926.1153', 'https://www.lni.wa.gov/safety-health/safety-topics/topics/silica', 1);

-- Asbestos
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-emp-163', 'WA-EMP-163', 'Washington Asbestos Abatement and Worker Safety', 'Asbestos abatement projects must be performed by L&I-certified asbestos workers supervised by competent persons. Certification requires approved training (32 hours initial, 8 hours annual refresher). Building owners must conduct asbestos surveys before renovation or demolition. Notification to L&I required 10 working days before abatement work begins. Worker exposure monitoring required. Medical surveillance for workers exposed above PEL. Disposal at approved facilities. Penalties up to $7,000 per violation.', 'EMPLOYMENT', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 49.26; WAC 296-65; WAC 296-62-077', 'https://www.lni.wa.gov/safety-health/safety-topics/topics/asbestos', 1);

-- Temporary Worker Protections
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-emp-164', 'WA-EMP-164', 'Washington Temporary Staffing Worker Protections', 'Temporary staffing agencies must be registered with L&I. Workers placed by staffing agencies are entitled to the same workplace safety protections as direct-hire employees. Staffing agency and host employer are jointly responsible for workplace safety. Staffing agency is the employer of record for workers'' comp, UI, and payroll taxes. Written assignment notifications must include wage rate, pay schedule, and worksite location. Both staffing agency and host employer may be liable for wage violations.', 'EMPLOYMENT', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 49.44.170; WAC 296-800', 'https://www.lni.wa.gov/workers-rights/', 1);

-- Gig Worker / App-Based Workers
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-emp-165', 'WA-EMP-165', 'Washington Transportation Network Company (TNC) Worker Protections', 'TNC drivers (Uber, Lyft) in Washington receive specific protections under HB 2076 (2022): minimum per-mile and per-minute pay rates, paid sick time (1 day per 30 days worked), workers'' comp coverage through a TNC driver account, deactivation protections (right to challenge deactivation), and expense reimbursement. These protections acknowledge TNC drivers as independent contractors while providing specified benefits. Administered by L&I and the Employment Security Department. Effective January 1, 2023.', 'EMPLOYMENT', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP"]', '2024-01-01', 'HB 2076 (2022); RCW 49.46.300', 'https://www.lni.wa.gov/', 1);

-- School-Related Leave
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-emp-166', 'WA-EMP-166', 'Washington Family Member Care and School Activities', 'Employees may use accrued paid sick leave to attend school conferences, school activities, or childcare activities related to their child. Paid sick leave covers closures of child''s school or daycare due to a public health emergency. PFML provides family leave for bonding with a new child, caring for a family member with a serious health condition, and qualifying military exigency. Family member defined broadly to include child, spouse, parent, sibling, grandparent, grandchild, and domestic partner.', 'EMPLOYMENT', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 49.46.210; RCW 50A.05.010', 'https://www.lni.wa.gov/workers-rights/leave/paid-sick-leave/', 1);

-- Severance and Separation
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-emp-167', 'WA-EMP-167', 'Washington Separation Agreement Requirements', 'Washington does not require severance pay. When offered, separation agreements must not include provisions waiving claims for sexual harassment or assault under RCW 49.44.211. NDAs may not prevent disclosure of workplace sexual harassment or assault. Employees 40+ must be given 21 days to consider agreements waiving age discrimination claims (ADEA) and 7-day revocation period. Consider that severance agreements may need to comply with the noncompete statute if they contain restrictive covenants.', 'EMPLOYMENT', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 49.44.211; 29 USC 626(f) (OWBPA)', 'https://www.lni.wa.gov/', 1);

-- Volunteer Firefighter Leave
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-emp-168', 'WA-EMP-168', 'Washington Volunteer Firefighter and Emergency Responder Leave', 'Employers may not terminate or discipline an employee who is a volunteer firefighter or reserve law enforcement officer for being late or absent due to responding to an emergency. Employee must provide reasonable notice when possible. Leave is unpaid unless employer policy provides otherwise. Employee must be restored to position upon return. Protection applies only when responding to emergencies per the fire department or law enforcement authority.', 'EMPLOYMENT', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 49.12.460', 'https://www.lni.wa.gov/workers-rights/leave/', 1);

-- Wage Theft
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-emp-169', 'WA-EMP-169', 'Washington Wage Theft Penalties', 'Employers who willfully and intentionally deprive employees of wages commit wage theft. Willful failure to pay wages subjects employer to double damages under RCW 49.52.070. Criminal penalties for wage theft: if under $750, gross misdemeanor; $750-$5,000, class C felony; over $5,000, class B felony. L&I processes wage complaints and may order payment of wages, interest, and penalties. Employees may also file civil action for unpaid wages plus attorney fees. 3-year statute of limitations for wage claims.', 'EMPLOYMENT', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 49.52.050; RCW 49.52.070; RCW 49.48.082', 'https://www.lni.wa.gov/workers-rights/wages/getting-paid/', 1);

-- Immigration-Related Employment
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-emp-170', 'WA-EMP-170', 'Washington Immigration-Related Employment Protections', 'Employers may not: (1) retaliate against an employee by threatening to report immigration status, (2) unfairly use immigration status to suppress wages or working conditions, (3) demand specific documents for I-9 verification (document abuse), (4) require employees to provide more immigration documents than required by law. Washington protects all workers regardless of immigration status for purposes of wage, safety, and discrimination laws. Workers'' comp benefits available regardless of immigration status.', 'EMPLOYMENT', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 49.60.180; 8 USC 1324b', 'https://www.lni.wa.gov/workers-rights/', 1);

-- Employee Benefit Protections
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-emp-171', 'WA-EMP-171', 'Washington Employee Benefit Continuation (Mini-COBRA)', 'Washington continuation coverage (mini-COBRA) applies to employers with 2-19 employees (smaller than federal COBRA threshold of 20+). Terminated employees and dependents may continue group health coverage for up to 18 months. Employee pays full premium plus 2% administrative fee. Election period is 60 days from qualifying event. Employer must notify employees of continuation rights within 10 days of qualifying event. Covers all types of group health insurance including dental and vision.', 'EMPLOYMENT', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 48.21.075 (group); RCW 48.44.165 (HMO); RCW 48.46.350', 'https://www.insurance.wa.gov/', 1);

-- Collective Bargaining
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-emp-172', 'WA-EMP-172', 'Washington Public Employee Collective Bargaining', 'Public employees in Washington have the right to organize and bargain collectively under RCW 41.56 (Public Employees'' Collective Bargaining Act), RCW 41.80 (State Civil Service), and RCW 28B.52 (Higher Education). Strikes by most public employees are prohibited. Impasse resolution through mediation and interest arbitration for police, fire, and certain other public employees. Right-to-work is NOT the law in Washington — both public and private sector unions may negotiate union security agreements.', 'EMPLOYMENT', 'STATE', 'WA', '["NONPROFIT"]', '2024-01-01', 'RCW 41.56.010; RCW 41.80.010', 'https://www.perc.wa.gov/', 1);

-- Personnel File Access
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-emp-173', 'WA-EMP-173', 'Washington Employee Personnel File Access', 'Washington does not have a specific statute granting employees the right to inspect personnel files. However, employees may request copies of personnel records related to their employment. Many employers voluntarily provide access as a best practice. In unionized workplaces, collective bargaining agreements often address personnel file access. Employees may request wage and hour records under RCW 49.46.070. Medical records must be maintained separately and kept confidential per ADA requirements.', 'EMPLOYMENT', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 49.46.070; Washington common law', 'https://www.lni.wa.gov/workers-rights/', 1);

-- Employer Liability for Employee Conduct
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-emp-174', 'WA-EMP-174', 'Washington Employer Liability — Negligent Hiring and Retention', 'Washington recognizes employer liability for negligent hiring, supervision, and retention. Employers must exercise reasonable care in hiring and retaining employees, particularly for positions involving public contact, access to vulnerable populations, or dangerous instruments. Background checks are not required by statute for most positions but are expected where the nature of the job warrants. Criminal history may be considered after initial screening (Fair Chance Act). Employer liability extends to off-duty conduct in some cases if foreseeable.', 'EMPLOYMENT', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'Carlsen v. Wackenhut Corp., 73 Wn. App. 247 (1994); RCW 49.94', 'https://www.lni.wa.gov/', 1);

-- Training Requirements
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-emp-175', 'WA-EMP-175', 'Washington Mandatory Employer Training Requirements', 'Required training includes: (1) workplace safety orientation for new employees (WAC 296-800-14010), (2) hazard communication/right-to-know (WAC 296-901), (3) first aid/CPR where required by risk classification, (4) sexual harassment prevention (recommended, required for some industries), (5) industry-specific training (food handling, asbestos, confined space). Training must be in a language understood by the employee. Records of training must be maintained. L&I provides free consultation and training resources.', 'EMPLOYMENT', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'WAC 296-800-14010; WAC 296-901', 'https://www.lni.wa.gov/safety-health/safety-training/', 1);

-- Travel Time Pay
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-emp-176', 'WA-EMP-176', 'Washington Travel Time Compensation', 'Ordinary commuting time (home to primary worksite) is not compensable. Travel during the workday between job sites is compensable work time. Travel to a different city for a one-day assignment is compensable minus normal commute time. Overnight travel during normal work hours is compensable. Travel required as a condition of employment that primarily benefits the employer is compensable. Washington follows federal FLSA interpretations for travel time. Employer must compensate at regular rate (not overtime unless hours exceed 40/week).', 'EMPLOYMENT', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'WAC 296-126-002; 29 CFR 785.35-785.41', 'https://www.lni.wa.gov/workers-rights/wages/getting-paid/', 1);

-- Tip Pooling
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-emp-177', 'WA-EMP-177', 'Washington Tip Protections', 'Tips belong to the employee. Employer may not take any portion of an employee''s tips. No tip credit against minimum wage (full minimum wage must be paid in addition to tips). Mandatory tip pooling among customarily tipped employees is permitted. Employers, managers, and supervisors may not participate in tip pools. Service charges imposed by the employer are not tips unless fully distributed to employees. If a service charge is retained by the employer, it must be disclosed to the customer.', 'EMPLOYMENT', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 49.46.160', 'https://www.lni.wa.gov/workers-rights/wages/tips/', 1);

-- Union Activity Protections
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-emp-178', 'WA-EMP-178', 'Washington Worker Organizing and Union Protections', 'Washington is NOT a right-to-work state. Union security clauses are permitted — employees may be required to pay union dues or equivalent fees as a condition of employment. Private sector organizing under federal NLRA. Public sector organizing under state law (RCW 41.56, 41.80). Employer may not interfere with, restrain, or coerce employees in the exercise of organizing rights. Captive audience meetings (mandatory employer anti-union meetings) may be restricted under state law developments.', 'EMPLOYMENT', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 41.56.040; 29 USC 157-158 (NLRA)', 'https://www.perc.wa.gov/', 1);

-- Age Discrimination
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-emp-179', 'WA-EMP-179', 'Washington Age Discrimination Protections', 'WLAD prohibits employment discrimination against persons age 40 and older. Applies to employers with 8+ employees (lower threshold than federal ADEA''s 20). Protects against age-based discrimination in hiring, termination, promotion, compensation, and terms of employment. Mandatory retirement prohibited except for bona fide executive or high policymaking positions. Waiver of age discrimination claims requires specific disclosures and 21/45-day consideration periods. Filed with WSHRC or as civil action within 3 years.', 'EMPLOYMENT', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 49.60.180; RCW 49.44.090', 'https://www.hum.wa.gov/', 1);

-- Genetic Information Discrimination
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-emp-180', 'WA-EMP-180', 'Washington Genetic Information Nondiscrimination', 'Employers may not require or request genetic testing as a condition of employment. May not use genetic information in employment decisions. Consistent with and exceeding federal GINA protections. Genetic information includes genetic tests, family medical history, and genetic counseling records. Health insurers may not use genetic information for coverage or premium decisions. Violations enforceable through WSHRC and civil action. Applies to all employers with 8+ employees.', 'EMPLOYMENT', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 49.44.180; RCW 49.60.180', 'https://www.hum.wa.gov/', 1);

-- Unemployment Insurance Claims
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-emp-181', 'WA-EMP-181', 'Washington Unemployment Insurance — Employer Response Obligations', 'When an employee files a UI claim, ESD mails a Notice of Claim to the employer. Employer must respond within 10 days with information about the separation (reason for termination, whether voluntary quit, any misconduct). Failure to respond timely may result in charges to the employer''s account regardless of the merits. Employer may appeal the initial determination within 30 days. Experience-rated employers pay higher rates when former employees collect benefits. Protest hearings available before an administrative law judge.', 'EMPLOYMENT', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 50.20.010; RCW 50.29.020', 'https://esd.wa.gov/employer-taxes', 1);

-- Shared Work Program
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-emp-182', 'WA-EMP-182', 'Washington Shared Work Program', 'Employers may apply to ESD for a Shared Work plan as an alternative to layoffs. Allows reduction of hours for a group of employees (10-50% reduction) while employees collect partial UI benefits for the lost hours. Minimum 10 employees in the affected unit. Plan approved for up to 12 months. Employees receive prorated UI benefits based on the percentage of hours reduced. Employer maintains the workforce and avoids rehiring costs. Application must demonstrate a plan to restore full-time hours.', 'EMPLOYMENT', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 50.60.020; RCW 50.60.030', 'https://esd.wa.gov/employer-taxes/shared-work', 1);

-- Restrictive Scheduling for Retail Workers
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-emp-183', 'WA-EMP-183', 'Washington Rest Between Shifts Requirement', 'Washington requires at least 8 hours between the end of one shift and the start of the next for most employees. Employers who schedule shifts with less than 8 hours between them must pay 1.5x the regular rate for the second shift. Exceptions for emergencies, shift trades initiated by the employee, and certain industries. Additional protections in Seattle under the Secure Scheduling Ordinance. Agricultural and healthcare workers may have specific rules. Compensatory rest time may be provided as alternative.', 'EMPLOYMENT', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'WAC 296-126-092; SMC 14.22 (Seattle)', 'https://www.lni.wa.gov/workers-rights/wages/getting-paid/breaks-rest-periods', 1);

-- Prevailing Wage
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-emp-184', 'WA-EMP-184', 'Washington Prevailing Wage Requirements', 'Contractors and subcontractors on public works projects must pay prevailing wages to all workers. Prevailing wage rates are set by L&I for each county and each trade. Include base wage and fringe benefits (health, pension, vacation). Statement of Intent to Pay Prevailing Wages filed before work begins. Affidavit of Wages Paid filed upon completion. Certified payroll records required. Apprentice utilization required on projects over $1 million. Penalties for violations include back wages, penalties up to $5,000 per violation, and debarment.', 'EMPLOYMENT', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 39.12.010; RCW 39.12.040; RCW 39.12.050', 'https://www.lni.wa.gov/licensing-permits/public-works-projects/', 1);

-- Telecommuting and Remote Work
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-emp-185', 'WA-EMP-185', 'Washington Remote Work and Telecommuting Compliance', 'No Washington law requires employers to offer remote work. When remote work is offered: all Washington wage and hour laws apply to employees working remotely in Washington regardless of employer location. Workers'' comp covers injuries during work at home during work hours. Employer must ensure home workspace complies with safety standards. Pay transparency rules apply to remote positions that could be performed in Washington. B&O and sales tax nexus considerations for businesses with remote workers in Washington.', 'EMPLOYMENT', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 49.46; RCW 51.08.013', 'https://www.lni.wa.gov/', 1);

-- Protection of Off-Duty Conduct
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-emp-186', 'WA-EMP-186', 'Washington Protection of Off-Duty Legal Conduct', 'Washington prohibits adverse employment action based on employee''s lawful off-duty use of cannabis (effective 2024). No broad off-duty conduct protection statute exists, but: employees may not be fired for lawful tobacco use off premises (RCW 49.44.170), lawful cannabis use per RCW 49.44.240, filing workers'' comp claims, serving on a jury, exercising voting rights, or engaging in protected political activity. Common law wrongful discharge claims may protect other lawful off-duty activities under public policy exception.', 'EMPLOYMENT', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 49.44.170; RCW 49.44.240', 'https://www.lni.wa.gov/workers-rights/', 1);

-- Caste Discrimination (Seattle)
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-emp-187', 'WA-EMP-187', 'Seattle Caste Discrimination Prohibition', 'Seattle became the first U.S. city to ban caste discrimination (Ordinance 126767, effective 2023). Caste added as a protected class under the Seattle Municipal Code. Prohibits discrimination in employment, housing, and public accommodations based on caste. Applies to all employers within Seattle city limits regardless of size. Enforced by the Seattle Office for Civil Rights. Remedies include compensatory damages, injunctive relief, and civil penalties. Complements WLAD protections for national origin and race.', 'EMPLOYMENT', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'Seattle Ordinance 126767 (2023); SMC 14.06', 'https://www.seattle.gov/civilrights/', 1);

-- Gig Economy / Platform Workers
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-emp-188', 'WA-EMP-188', 'Washington App-Based Delivery Driver Protections', 'App-based delivery drivers (DoorDash, Instacart, etc.) receive protections under various Washington proposals and local ordinances. Seattle passed PayUp legislation requiring minimum per-delivery pay, transparency in pay algorithms, and protection from deactivation without cause. Statewide efforts continue to address gig worker classification and benefits. Delivery drivers must be covered under employer workers'' comp or carry their own coverage. City-specific regulations may impose additional requirements.', 'EMPLOYMENT', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP"]', '2024-01-01', 'Seattle Ordinance 126595 (PayUp); RCW 49.46', 'https://www.seattle.gov/laborstandards/', 1);

-- Hazardous Chemical Right-to-Know
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-emp-189', 'WA-EMP-189', 'Washington Worker Right-to-Know — Hazard Communication', 'Employers must implement a written hazard communication program per WAC 296-901. Must maintain Safety Data Sheets (SDS) for all hazardous chemicals in the workplace. Employees must have access to SDS during all work shifts. Chemical containers must be labeled with product identity and hazard warnings. Training required at initial assignment and when new chemical hazards are introduced. Program must include a list of all hazardous chemicals present. Employees have the right to obtain SDS for any chemical they work with.', 'EMPLOYMENT', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'WAC 296-901; RCW 49.70.020', 'https://www.lni.wa.gov/safety-health/safety-topics/topics/hazard-communication', 1);

-- AI in Employment
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-emp-190', 'WA-EMP-190', 'Washington AI and Automated Decision-Making in Employment', 'Washington has enacted the My Health My Data Act (2023) restricting use of health data including in employment contexts. Additional legislation addressing AI in hiring and employment decisions is under consideration. Employers using automated employment decision tools must ensure compliance with WLAD anti-discrimination requirements — AI tools that produce disparate impact may violate state law. Seattle has explored algorithmic accountability requirements. Employers should audit AI hiring tools for bias and maintain records of tool validation.', 'EMPLOYMENT', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 19.373 (My Health My Data); RCW 49.60.180', 'https://www.atg.wa.gov/', 1);
